   1→use crate::context::{ContextConfig, compact_messages};
   2→use crate::error::CoreError;
   3→use crate::protocol::{
   4→    AgentEvent, ChatMessage, ModelDirective, ModelStopReason, ModelTurn, RunStopReason, TokenUsage,
   5→    ToolCall, ToolDefinition, ToolResult, ToolResultSummary,
   6→};
   7→use crate::state::AppState;
   8→use std::collections::BTreeMap;
   9→use std::sync::Arc;
  10→use std::sync::atomic::{AtomicBool, Ordering};
  11→
  12→/// Hook trait for approval gates, allowing the agent loop to wire event handlers
  13→/// into the gate without depending on the concrete `ApprovalGate` type.
  14→pub trait ApprovalGateHook: Send + Sync {
  15→    fn set_event_handler(&self, handler: Arc<dyn Fn(AgentEvent) + Send + Sync>);
  16→    fn clear_event_handler(&self);
  17→}
  18→
  19→/// Trait for resolving pending approvals from HTTP endpoints.
  20→pub trait ApprovalResolver: Send + Sync {
  21→    fn resolve_approval(&self, approval_id: &str, decision: &str, reason: Option<String>) -> bool;
  22→    fn pending_approval_ids(&self) -> Vec<String>;
  23→}
  24→
  25→#[derive(Debug, Clone)]
  26→pub struct ProviderRequest {
  27→    pub run_id: String,
  28→    pub session_id: String,
  29→    pub iteration: u32,
  30→    pub messages: Vec<ChatMessage>,
  31→    pub tools: Vec<ToolDefinition>,
  32→    pub state: AppState,
  33→}
  34→
  35→pub trait Provider: Send + Sync {
  36→    fn name(&self) -> &str;
  37→    fn complete(&self, request: &ProviderRequest) -> Result<ModelTurn, CoreError>;
  38→}
  39→
  40→#[derive(Debug, Clone)]
  41→pub struct ToolContext {
  42→    pub run_id: String,
  43→    pub session_id: String,
  44→    pub iteration: u32,
  45→}
  46→
  47→pub trait Tool: Send + Sync {
  48→    fn definition(&self) -> ToolDefinition;
  49→    fn execute(&self, call: &ToolCall, ctx: &ToolContext) -> Result<ToolResult, CoreError>;
  50→}
  51→
  52→pub trait Middleware: Send + Sync {
  53→    fn before_model_call(&self, _request: &ProviderRequest) -> Result<(), CoreError> {
  54→        Ok(())
  55→    }
  56→
  57→    fn after_model_call(
  58→        &self,
  59→        _request: &ProviderRequest,
  60→        _response: &ModelTurn,
  61→    ) -> Result<(), CoreError> {
  62→        Ok(())
  63→    }
  64→
  65→    fn pre_tool_call(&self, _context: &ToolContext, _call: &ToolCall) -> Result<(), CoreError> {
  66→        Ok(())
  67→    }
  68→
  69→    fn post_tool_call(
  70→        &self,
  71→        _context: &ToolContext,
  72→        _result: &ToolResult,
  73→    ) -> Result<(), CoreError> {
  74→        Ok(())
  75→    }
  76→
  77→    fn on_run_finished(&self, _output: &RunOutput) -> Result<(), CoreError> {
  78→        Ok(())
  79→    }
  80→}
  81→
  82→#[derive(Clone, Default)]
  83→pub struct ToolRegistry {
  84→    tools: BTreeMap<String, Arc<dyn Tool>>,
  85→}
  86→
  87→impl ToolRegistry {
  88→    pub fn register<T: Tool + 'static>(&mut self, tool: T) {
  89→        self.tools
  90→            .insert(tool.definition().name.clone(), Arc::new(tool));
  91→    }
  92→
  93→    pub fn get(&self, tool_name: &str) -> Option<Arc<dyn Tool>> {
  94→        self.tools.get(tool_name).cloned()
  95→    }
  96→
  97→    pub fn definitions(&self) -> Vec<ToolDefinition> {
  98→        self.tools.values().map(|tool| tool.definition()).collect()
  99→    }
 100→}
