 102→#[derive(Debug, Clone)]
 103→pub struct OrchestratorConfig {
 104→    pub max_iterations: u32,
 105→    /// Context window management configuration.
 106→    /// When set, messages are compacted before each provider call to stay within limits.
 107→    pub context: Option<ContextConfig>,
 108→    /// Context compiler configuration for assembling system prompts from typed blocks.
 109→    /// When set, context blocks are compiled into system messages with budget enforcement.
 110→    pub context_compiler: Option<crate::context_compiler::ContextCompilerConfig>,
 111→}
 112→
 113→impl Default for OrchestratorConfig {
 114→    fn default() -> Self {
 115→        Self {
 116→            max_iterations: 24,
 117→            context: Some(ContextConfig::default()),
 118→            context_compiler: None,
 119→        }
 120→    }
 121→}
