 123→#[derive(Debug, Clone)]
 124→pub struct RunInput {
 125→    pub run_id: String,
 126→    pub session_id: String,
 127→    pub branch_id: String,
 128→    pub messages: Vec<ChatMessage>,
 129→    pub state: AppState,
 130→}
 131→
 132→#[derive(Debug, Clone)]
 133→pub struct RunOutput {
 134→    pub run_id: String,
 135→    pub session_id: String,
 136→    pub branch_id: String,
 137→    pub events: Vec<AgentEvent>,
 138→    pub messages: Vec<ChatMessage>,
 139→    pub state: AppState,
 140→    pub reason: RunStopReason,
 141→    pub final_answer: Option<String>,
 142→    /// Accumulated token usage across all iterations.
 143→    pub total_usage: TokenUsage,
 144→}
 145→
 146→pub struct Orchestrator {
 147→    provider: Arc<std::sync::RwLock<Arc<dyn Provider>>>,
 148→    tools: ToolRegistry,
 149→    middlewares: Vec<Arc<dyn Middleware>>,
 150→    config: OrchestratorConfig,
 151→}
 152→
 153→impl Orchestrator {
 154→    pub fn new(
 155→        provider: Arc<dyn Provider>,
 156→        tools: ToolRegistry,
 157→        middlewares: Vec<Arc<dyn Middleware>>,
 158→        config: OrchestratorConfig,
 159→    ) -> Self {
 160→        Self {
 161→            provider: Arc::new(std::sync::RwLock::new(provider)),
 162→            tools,
 163→            middlewares,
 164→            config,
 165→        }
 166→    }
 167→
 168→    /// Swap the active provider at runtime. Returns the name of the new provider.
 169→    pub fn swap_provider(&self, new_provider: Arc<dyn Provider>) -> String {
 170→        let name = new_provider.name().to_string();
 171→        let mut guard = self.provider.write().expect("provider lock poisoned");
 172→        *guard = new_provider;
 173→        name
 174→    }
 175→
 176→    /// Get the current provider name.
 177→    pub fn provider_name(&self) -> String {
 178→        let guard = self.provider.read().expect("provider lock poisoned");
 179→        guard.name().to_string()
 180→    }
 181→
 182→    pub fn run(&self, input: RunInput, event_handler: impl FnMut(AgentEvent)) -> RunOutput {
 183→        self.run_cancellable(input, None, event_handler)
 184→    }
 185→
 186→    /// Run the orchestrator loop with an optional cancellation flag.
 187→    ///
 188→    /// If `cancel` is provided and set to `true` during execution,
 189→    /// the loop will stop at the next iteration boundary.
 190→    pub fn run_cancellable(
 191→        &self,
 192→        input: RunInput,
 193→        cancel: Option<&Arc<AtomicBool>>,
 194→        mut event_handler: impl FnMut(AgentEvent),
 195→    ) -> RunOutput {
 196→        let mut events = Vec::new();
 197→        let mut messages = input.messages;
 198→        let mut state = input.state;
 199→        let mut final_answer: Option<String> = None;
 200→        let mut stop_reason = RunStopReason::BudgetExceeded;
 201→        let mut total_iterations = 0;
 202→        let mut total_usage = TokenUsage::default();
 203→
 204→        // Acquire provider reference for this run
 205→        let provider = self
 206→            .provider
 207→            .read()
 208→            .expect("provider lock poisoned")
 209→            .clone();
 210→
 211→        let start_event = AgentEvent::RunStarted {
 212→            run_id: input.run_id.clone(),
 213→            session_id: input.session_id.clone(),
 214→            provider: provider.name().to_string(),
 215→            max_iterations: self.config.max_iterations,
 216→        };
 217→        event_handler(start_event.clone());
 218→        events.push(start_event);
 219→
 220→        for iteration in 1..=self.config.max_iterations {
 221→            // Check cancellation at each iteration boundary
 222→            if let Some(flag) = cancel {
 223→                if flag.load(Ordering::Relaxed) {
 224→                    stop_reason = RunStopReason::Cancelled;
 225→                    let err_event = AgentEvent::RunErrored {
 226→                        run_id: input.run_id.clone(),
 227→                        session_id: input.session_id.clone(),
 228→                        error: "run cancelled".to_string(),
 229→                    };
 230→                    event_handler(err_event.clone());
 231→                    events.push(err_event);
 232→                    break;
 233→                }
 234→            }
 235→
 236→            total_iterations = iteration;
 237→            let iter_event = AgentEvent::IterationStarted {
 238→                run_id: input.run_id.clone(),
 239→                session_id: input.session_id.clone(),
 240→                iteration,
 241→            };
 242→            event_handler(iter_event.clone());
 243→            events.push(iter_event);
 244→
 245→            // Context window compaction: trim messages before sending to provider
 246→            if let Some(ref ctx_config) = self.config.context {
 247→                if let Some(result) = compact_messages(&messages, ctx_config) {
 248→                    let compact_event = AgentEvent::ContextCompacted {
 249→                        run_id: input.run_id.clone(),
 250→                        session_id: input.session_id.clone(),
 251→                        iteration,
 252→                        dropped_count: result.dropped_count,
 253→                        tokens_before: result.tokens_before,
 254→                        tokens_after: result.tokens_after,
 255→                    };
 256→                    event_handler(compact_event.clone());
 257→                    events.push(compact_event);
 258→                    messages = result.messages;
 259→                }
 260→            }
 261→
 262→            let provider_request = ProviderRequest {
 263→                run_id: input.run_id.clone(),
 264→                session_id: input.session_id.clone(),
 265→                iteration,
 266→                messages: messages.clone(),
 267→                tools: self.tools.definitions(),
 268→                state: state.clone(),
 269→            };
 270→
 271→            if let Err(err) = self.run_before_model(&provider_request) {
 272→                stop_reason = RunStopReason::BlockedByPolicy;
 273→                let err_event = AgentEvent::RunErrored {
 274→                    run_id: input.run_id.clone(),
 275→                    session_id: input.session_id.clone(),
 276→                    error: err.to_string(),
 277→                };
 278→                event_handler(err_event.clone());
 279→                events.push(err_event);
 280→                break;
 281→            }
 282→
 283→            let model_turn = match provider.complete(&provider_request) {
 284→                Ok(turn) => turn,
 285→                Err(err) => {
 286→                    stop_reason = RunStopReason::Error;
 287→                    let err_event = AgentEvent::RunErrored {
 288→                        run_id: input.run_id.clone(),
 289→                        session_id: input.session_id.clone(),
 290→                        error: err.to_string(),
 291→                    };
 292→                    event_handler(err_event.clone());
 293→                    events.push(err_event);
 294→                    break;
 295→                }
 296→            };
 297→
 298→            if let Err(err) = self.run_after_model(&provider_request, &model_turn) {
 299→                stop_reason = RunStopReason::BlockedByPolicy;
 300→                let err_event = AgentEvent::RunErrored {
 301→                    run_id: input.run_id.clone(),
 302→                    session_id: input.session_id.clone(),
 303→                    error: err.to_string(),
 304→                };
 305→                event_handler(err_event.clone());
 306→                events.push(err_event);
 307→                break;
 308→            }
 309→
 310→            // Accumulate token usage if reported
 311→            if let Some(ref usage) = model_turn.usage {
 312→                total_usage.accumulate(usage);
 313→            }
 314→
 315→            let output_event = AgentEvent::ModelOutput {
 316→                run_id: input.run_id.clone(),
 317→                session_id: input.session_id.clone(),
 318→                iteration,
 319→                stop_reason: model_turn.stop_reason,
 320→                directive_count: model_turn.directives.len(),
 321→                usage: model_turn.usage,
 322→            };
 323→            event_handler(output_event.clone());
 324→            events.push(output_event);
 325→
 326→            let mut requested_tool = false;
 327→
 328→            for directive in model_turn.directives {
 329→                match directive {
 330→                    ModelDirective::Text { delta } => {
 331→                        let delta_event = AgentEvent::TextDelta {
 332→                            run_id: input.run_id.clone(),
 333→                            session_id: input.session_id.clone(),
 334→                            iteration,
 335→                            delta: delta.clone(),
 336→                        };
 337→                        event_handler(delta_event.clone());
 338→                        events.push(delta_event);
 339→                        messages.push(ChatMessage::assistant(delta));
 340→                    }
 341→                    ModelDirective::ToolCall { call } => {
 342→                        requested_tool = true;
 343→                        let tc_event = AgentEvent::ToolCallRequested {
 344→                            run_id: input.run_id.clone(),
 345→                            session_id: input.session_id.clone(),
 346→                            iteration,
 347→                            call: call.clone(),
 348→                        };
 349→                        event_handler(tc_event.clone());
 350→                        events.push(tc_event);
 351→
 352→                        let context = ToolContext {
 353→                            run_id: input.run_id.clone(),
 354→                            session_id: input.session_id.clone(),
 355→                            iteration,
 356→                        };
 357→
 358→                        if let Err(err) = self.run_pre_tool(&context, &call) {
 359→                            stop_reason = RunStopReason::BlockedByPolicy;
 360→                            let err_event = AgentEvent::ToolCallFailed {
 361→                                run_id: input.run_id.clone(),
 362→                                session_id: input.session_id.clone(),
 363→                                iteration,
 364→                                call_id: call.call_id.clone(),
 365→                                tool_name: call.tool_name.clone(),
 366→                                error: err.to_string(),
 367→                            };
 368→                            event_handler(err_event.clone());
 369→                            events.push(err_event);
 370→                            break;
 371→                        }
 372→
 373→                        let Some(tool) = self.tools.get(&call.tool_name) else {
 374→                            stop_reason = RunStopReason::Error;
 375→                            let err_event = AgentEvent::ToolCallFailed {
 376→                                run_id: input.run_id.clone(),
 377→                                session_id: input.session_id.clone(),
 378→                                iteration,
 379→                                call_id: call.call_id.clone(),
 380→                                tool_name: call.tool_name.clone(),
 381→                                error: format!(
 382→                                    "{}",
 383→                                    CoreError::ToolNotFound {
 384→                                        tool_name: call.tool_name.clone(),
 385→                                    }
 386→                                ),
 387→                            };
 388→                            event_handler(err_event.clone());
 389→                            events.push(err_event);
 390→                            break;
 391→                        };
 392→
 393→                        match tool.execute(&call, &context) {
 394→                            Ok(result) => {
 395→                                if let Some(patch) = &result.state_patch {
 396→                                    match state.apply_patch(patch) {
 397→                                        Ok(()) => {
 398→                                            let patch_event = AgentEvent::StatePatched {
 399→                                                run_id: input.run_id.clone(),
 400→                                                session_id: input.session_id.clone(),
 401→                                                iteration,
 402→                                                patch: patch.clone(),
 403→                                                revision: state.revision,
 404→                                            };
 405→                                            event_handler(patch_event.clone());
 406→                                            events.push(patch_event);
 407→                                        }
 408→                                        Err(err) => {
 409→                                            stop_reason = RunStopReason::Error;
 410→                                            let err_event = AgentEvent::ToolCallFailed {
 411→                                                run_id: input.run_id.clone(),
 412→                                                session_id: input.session_id.clone(),
 413→                                                iteration,
 414→                                                call_id: call.call_id.clone(),
 415→                                                tool_name: call.tool_name.clone(),
 416→                                                error: err.to_string(),
 417→                                            };
 418→                                            event_handler(err_event.clone());
 419→                                            events.push(err_event);
 420→                                            break;
 421→                                        }
 422→                                    }
 423→                                }
 424→
 425→                                if let Err(err) = self.run_post_tool(&context, &result) {
 426→                                    stop_reason = RunStopReason::BlockedByPolicy;
 427→                                    let err_event = AgentEvent::ToolCallFailed {
 428→                                        run_id: input.run_id.clone(),
 429→                                        session_id: input.session_id.clone(),
 430→                                        iteration,
 431→                                        call_id: call.call_id.clone(),
 432→                                        tool_name: call.tool_name.clone(),
 433→                                        error: err.to_string(),
 434→                                    };
 435→                                    event_handler(err_event.clone());
 436→                                    events.push(err_event);
 437→                                    break;
 438→                                }
 439→
 440→                                let completed_event = AgentEvent::ToolCallCompleted {
 441→                                    run_id: input.run_id.clone(),
 442→                                    session_id: input.session_id.clone(),
 443→                                    iteration,
 444→                                    result: ToolResultSummary::from(&result),
 445→                                };
 446→                                event_handler(completed_event.clone());
 447→                                events.push(completed_event);
 448→
 449→                                messages.push(ChatMessage::tool_result(
 450→                                    &result.call_id,
 451→                                    serde_json::to_string(&result.output)
 452→                                        .unwrap_or_else(|_| "{}".to_string()),
 453→                                ));
 454→                            }
 455→                            Err(err) => {
 456→                                stop_reason = RunStopReason::Error;
 457→                                let err_event = AgentEvent::ToolCallFailed {
 458→                                    run_id: input.run_id.clone(),
 459→                                    session_id: input.session_id.clone(),
 460→                                    iteration,
 461→                                    call_id: call.call_id.clone(),
 462→                                    tool_name: call.tool_name.clone(),
 463→                                    error: err.to_string(),
 464→                                };
 465→                                event_handler(err_event.clone());
 466→                                events.push(err_event);
 467→                                break;
 468→                            }
 469→                        }
 470→                    }
 471→                    ModelDirective::StatePatch { patch } => match state.apply_patch(&patch) {
 472→                        Ok(()) => {
 473→                            let patch_event = AgentEvent::StatePatched {
 474→                                run_id: input.run_id.clone(),
 475→                                session_id: input.session_id.clone(),
 476→                                iteration,
 477→                                patch: patch.clone(),
 478→                                revision: state.revision,
 479→                            };
 480→                            event_handler(patch_event.clone());
 481→                            events.push(patch_event);
 482→                        }
 483→                        Err(err) => {
 484→                            stop_reason = RunStopReason::Error;
 485→                            let err_event = AgentEvent::RunErrored {
 486→                                run_id: input.run_id.clone(),
 487→                                session_id: input.session_id.clone(),
 488→                                error: err.to_string(),
 489→                            };
 490→                            event_handler(err_event.clone());
 491→                            events.push(err_event);
 492→                            break;
 493→                        }
 494→                    },
 495→                    ModelDirective::FinalAnswer { text } => {
 496→                        final_answer = Some(text.clone());
 497→                        let delta_event = AgentEvent::TextDelta {
 498→                            run_id: input.run_id.clone(),
 499→                            session_id: input.session_id.clone(),
 500→                            iteration,
 501→                            delta: text.clone(),
 502→                        };
 503→                        event_handler(delta_event.clone());
 504→                        events.push(delta_event);
 505→                        messages.push(ChatMessage::assistant(text));
 506→                    }
 507→                }
 508→            }
 509→
 510→            if matches!(
 511→                stop_reason,
 512→                RunStopReason::Error | RunStopReason::BlockedByPolicy | RunStopReason::Cancelled
 513→            ) {
 514→                break;
 515→            }
 516→
 517→            match model_turn.stop_reason {
 518→                ModelStopReason::EndTurn => {
 519→                    stop_reason = RunStopReason::Completed;
 520→                    break;
 521→                }
 522→                ModelStopReason::NeedsUser => {
 523→                    stop_reason = RunStopReason::NeedsUser;
 524→                    break;
 525→                }
 526→                ModelStopReason::Safety => {
 527→                    stop_reason = RunStopReason::BlockedByPolicy;
 528→                    break;
 529→                }
 530→                ModelStopReason::ToolUse => {
 531→                    if !requested_tool {
 532→                        stop_reason = RunStopReason::Error;
 533→                        let err_event = AgentEvent::RunErrored {
 534→                            run_id: input.run_id.clone(),
 535→                            session_id: input.session_id.clone(),
 536→                            error: "model requested tool_use stop reason without tool call"
 537→                                .to_string(),
 538→                        };
 539→                        event_handler(err_event.clone());
 540→                        events.push(err_event);
 541→                        break;
 542→                    }
 543→                }
 544→                ModelStopReason::MaxTokens | ModelStopReason::Unknown => {
 545→                    if !requested_tool {
 546→                        stop_reason = RunStopReason::Error;
 547→                        let err_event = AgentEvent::RunErrored {
 548→                            run_id: input.run_id.clone(),
 549→                            session_id: input.session_id.clone(),
 550→                            error: "model returned non-terminal stop reason without tool call"
 551→                                .to_string(),
 552→                        };
 553→                        event_handler(err_event.clone());
 554→                        events.push(err_event);
 555→                        break;
 556→                    }
 557→                }
 558→            }
 559→        }
 560→
 561→        if total_iterations == self.config.max_iterations
 562→            && stop_reason == RunStopReason::BudgetExceeded
 563→        {
 564→            let err_event = AgentEvent::RunErrored {
 565→                run_id: input.run_id.clone(),
 566→                session_id: input.session_id.clone(),
 567→                error: "max iteration budget exceeded".to_string(),
 568→            };
 569→            event_handler(err_event.clone());
 570→            events.push(err_event);
 571→        }
 572→
 573→        let finished_event = AgentEvent::RunFinished {
 574→            run_id: input.run_id.clone(),
 575→            session_id: input.session_id.clone(),
 576→            reason: stop_reason,
 577→            total_iterations,
 578→            final_answer: final_answer.clone(),
 579→        };
 580→        event_handler(finished_event.clone());
 581→        events.push(finished_event);
 582→
 583→        let output = RunOutput {
 584→            run_id: input.run_id,
 585→            session_id: input.session_id,
 586→            branch_id: input.branch_id,
 587→            events,
 588→            messages,
 589→            state,
 590→            reason: stop_reason,
 591→            final_answer,
 592→            total_usage,
 593→        };
 594→
 595→        let _ = self
 596→            .middlewares
 597→            .iter()
 598→            .try_for_each(|middleware| middleware.on_run_finished(&output));
 599→
 600→        output
 601→    }
