 603→    fn run_before_model(&self, request: &ProviderRequest) -> Result<(), CoreError> {
 604→        self.middlewares
 605→            .iter()
 606→            .try_for_each(|middleware| middleware.before_model_call(request))
 607→    }
 608→
 609→    fn run_after_model(
 610→        &self,
 611→        request: &ProviderRequest,
 612→        response: &ModelTurn,
 613→    ) -> Result<(), CoreError> {
 614→        self.middlewares
 615→            .iter()
 616→            .try_for_each(|middleware| middleware.after_model_call(request, response))
 617→    }
 618→
 619→    fn run_pre_tool(&self, context: &ToolContext, call: &ToolCall) -> Result<(), CoreError> {
 620→        self.middlewares
 621→            .iter()
 622→            .try_for_each(|middleware| middleware.pre_tool_call(context, call))
 623→    }
 624→
 625→    fn run_post_tool(&self, context: &ToolContext, result: &ToolResult) -> Result<(), CoreError> {
 626→        self.middlewares
 627→            .iter()
 628→            .try_for_each(|middleware| middleware.post_tool_call(context, result))
 629→    }
 630→}
