            |_| {},
        );

        assert_eq!(output.reason, RunStopReason::Completed);
        assert_eq!(output.total_usage.input_tokens, 300);
        assert_eq!(output.total_usage.output_tokens, 80);
        assert_eq!(output.total_usage.total(), 380);
    }
}

