 28→impl OpenAiConfig {
 29→    /// Create config for OpenAI from environment variables.
 30→    pub fn openai_from_env() -> Result<Self, CoreError> {
 31→        let api_key = std::env::var("OPENAI_API_KEY").map_err(|_| {
 32→            CoreError::Provider("OPENAI_API_KEY environment variable not set".to_string())
 33→        })?;
 34→
 35→        let model = std::env::var("OPENAI_MODEL").unwrap_or_else(|_| "gpt-4o".to_string());
 36→        let max_tokens = std::env::var("OPENAI_MAX_TOKENS")
 37→            .ok()
 38→            .and_then(|s| s.parse().ok())
 39→            .unwrap_or(4096);
 40→        let base_url = std::env::var("OPENAI_BASE_URL")
 41→            .unwrap_or_else(|_| "https://api.openai.com".to_string());
 42→
 43→        Ok(Self {
 44→            api_key,
 45→            model,
 46→            max_tokens,
