 52→    /// Create config for Ollama from environment variables.
 53→    /// Defaults to localhost:11434 with no API key.
 54→    pub fn ollama_from_env() -> Result<Self, CoreError> {
 55→        let model = std::env::var("OLLAMA_MODEL").unwrap_or_else(|_| "llama3.2".to_string());
 56→        let max_tokens = std::env::var("OLLAMA_MAX_TOKENS")
 57→            .ok()
 58→            .and_then(|s| s.parse().ok())
 59→            .unwrap_or(4096);
 60→        let base_url = std::env::var("OLLAMA_BASE_URL")
 61→            .unwrap_or_else(|_| "http://localhost:11434".to_string());
