 72→
 73→/// Provider implementation for any OpenAI-compatible chat completions API.
 74→///
 75→/// Supports tool calling via the `tools` parameter with `function` type.
 76→/// Works with OpenAI, Ollama, Together, Groq, LM Studio, vLLM, etc.
 77→pub struct OpenAiCompatibleProvider {
 78→    config: OpenAiConfig,
 79→    client: reqwest::blocking::Client,
 80→}
 81→
 82→impl OpenAiCompatibleProvider {
 83→    pub fn new(config: OpenAiConfig) -> Self {
 84→        let client = reqwest::blocking::Client::builder()
 85→            .timeout(std::time::Duration::from_secs(120))
 86→            .build()
 87→            .unwrap_or_else(|_| reqwest::blocking::Client::new());
 88→        Self { config, client }
 89→    }
 90→
 91→    fn build_messages(&self, messages: &[ChatMessage]) -> Vec<ApiMessage> {
 92→        messages
 93→            .iter()
 94→            .map(|msg| {
 95→                let (role, tool_call_id) = match msg.role {
 96→                    Role::System => ("system", None),
 97→                    Role::User => ("user", None),
 98→                    Role::Assistant => ("assistant", None),
 99→                    Role::Tool => ("tool", msg.tool_call_id.clone()),
100→                };
101→                ApiMessage {
102→                    role: role.to_string(),
103→                    content: Some(msg.content.clone()),
104→                    tool_call_id,
105→                    tool_calls: None,
106→                }
107→            })
108→            .collect()
109→    }
110→
111→    fn convert_tools(&self, tools: &[ToolDefinition]) -> Vec<ApiTool> {
112→        tools
113→            .iter()
114→            .map(|t| ApiTool {
115→                r#type: "function".to_string(),
116→                function: ApiFunction {
117→                    name: t.name.clone(),
118→                    description: t.description.clone(),
119→                    parameters: t.input_schema.clone(),
120→                    strict: Some(true),
121→                },
122→            })
123→            .collect()
124→    }
125→
126→    fn parse_response(&self, response: ApiResponse) -> Result<ModelTurn, CoreError> {
127→        let choice = response
128→            .choices
129→            .into_iter()
130→            .next()
131→            .ok_or_else(|| CoreError::Provider("OpenAI response had no choices".to_string()))?;
132→
133→        let mut directives = Vec::new();
134→
135→        // Handle text content
136→        if let Some(content) = &choice.message.content {
137→            if !content.is_empty() {
138→                directives.push(ModelDirective::Text {
139→                    delta: content.clone(),
140→                });
141→            }
142→        }
143→
144→        // Handle tool calls
145→        if let Some(tool_calls) = &choice.message.tool_calls {
146→            for tc in tool_calls {
147→                let input: Value =
148→                    serde_json::from_str(&tc.function.arguments).unwrap_or_else(|_| json!({}));
149→                directives.push(ModelDirective::ToolCall {
150→                    call: ToolCall {
151→                        call_id: tc.id.clone(),
152→                        tool_name: tc.function.name.clone(),
153→                        input,
154→                    },
155→                });
156→            }
157→        }
158→
159→        let stop_reason = match choice.finish_reason.as_deref() {
160→            Some("stop") => ModelStopReason::EndTurn,
161→            Some("tool_calls") => ModelStopReason::ToolUse,
162→            Some("length") => ModelStopReason::MaxTokens,
163→            Some("content_filter") => ModelStopReason::Safety,
164→            _ => ModelStopReason::Unknown,
165→        };
166→
167→        let usage = response.usage.map(|u| TokenUsage {
168→            input_tokens: u.prompt_tokens,
169→            output_tokens: u.completion_tokens,
170→            cache_read_tokens: 0,
171→            cache_creation_tokens: 0,
172→        });
173→
174→        Ok(ModelTurn {
175→            directives,
176→            stop_reason,
177→            usage,
178→        })
179→    }
180→
181→    /// Execute with retry logic for transient errors (429, 5xx).
182→    fn execute_with_retry(
183→        &self,
184→        body: &Value,
185→        url: &str,
186→        max_retries: u32,
187→    ) -> Result<String, CoreError> {
188→        let mut last_error = None;
189→        let base_delay = std::time::Duration::from_millis(200);
190→
191→        for attempt in 0..=max_retries {
192→            if attempt > 0 {
193→                let delay = base_delay * 2u32.pow(attempt - 1);
194→                std::thread::sleep(delay);
195→            }
196→
197→            let mut request = self
198→                .client
199→                .post(url)
200→                .header("content-type", "application/json");
201→
202→            // Only add Authorization header if API key is non-empty
203→            if !self.config.api_key.is_empty() {
204→                request =
205→                    request.header("authorization", format!("Bearer {}", self.config.api_key));
206→            }
207→
208→            let response = match request.json(body).send() {
209→                Ok(resp) => resp,
210→                Err(e) if e.is_timeout() && attempt < max_retries => {
211→                    last_error = Some(format!("timeout: {e}"));
212→                    continue;
213→                }
214→                Err(e) => return Err(CoreError::Provider(format!("HTTP request failed: {e}"))),
215→            };
216→
217→            let status = response.status();
218→            let response_text = response
219→                .text()
220→                .map_err(|e| CoreError::Provider(format!("failed to read response: {e}")))?;
221→
222→            // Retry on transient errors
223→            if (status.as_u16() == 429 || status.is_server_error()) && attempt < max_retries {
224→                last_error = Some(format!("{status}: {response_text}"));
225→                continue;
226→            }
227→
228→            if !status.is_success() {
229→                return Err(CoreError::Provider(format!(
230→                    "{} API returned {status}: {response_text}",
231→                    self.config.provider_name
232→                )));
233→            }
234→
235→            return Ok(response_text);
236→        }
237→
238→        Err(CoreError::Provider(format!(
239→            "{} API failed after {} retries: {}",
240→            self.config.provider_name,
241→            max_retries,
242→            last_error.unwrap_or_default()
243→        )))
244→    }
245→}
