247→impl Provider for OpenAiCompatibleProvider {
248→    fn name(&self) -> &str {
249→        &self.config.model
250→    }
251→
252→    fn complete(&self, request: &ProviderRequest) -> Result<ModelTurn, CoreError> {
253→        let api_messages = self.build_messages(&request.messages);
254→        let api_tools = self.convert_tools(&request.tools);
255→
256→        let mut body = json!({
257→            "model": self.config.model,
258→            "messages": api_messages,
259→            "max_tokens": self.config.max_tokens,
260→        });
261→
262→        if !api_tools.is_empty() {
263→            body["tools"] = serde_json::to_value(&api_tools)
264→                .map_err(|e| CoreError::Provider(format!("failed to serialize tools: {e}")))?;
265→        }
266→
267→        let url = format!("{}/v1/chat/completions", self.config.base_url);
268→        let response_text = self.execute_with_retry(&body, &url, 3)?;
269→
270→        let api_response: ApiResponse = serde_json::from_str(&response_text).map_err(|e| {
271→            CoreError::Provider(format!(
272→                "failed to parse {} response: {e}\nBody: {}",
273→                self.config.provider_name,
274→                &response_text[..response_text.len().min(500)]
275→            ))
276→        })?;
277→
278→        self.parse_response(api_response)
279→    }
280→}
