270→    let session_id = SessionId::from_string(session_id);
271→    let branch = query
272→        .branch
273→        .as_deref()
274→        .map(BranchId::from_string)
275→        .unwrap_or_else(BranchId::main);
276→    let events = state
277→        .runtime
278→        .read_events_on_branch(&session_id, &branch, 1, 4096)
279→        .await
280→        .map_err(internal_error)?;
281→
282→    let mut latest_state = AgentStateVector::default();
283→    let mut mode = OperatingMode::Explore;
284→    let mut version = 0_u64;
285→    for event in events {
286→        version = event.sequence;
287→        if let EventKind::StateEstimated {
288→            state,
289→            mode: event_mode,
290→        } = event.kind
291→        {
292→            latest_state = state;
293→            mode = event_mode;
294→        }
295→    }
296→
297→    Ok(Json(StateResponse {
298→        session_id,
299→        branch,
300→        mode,
301→        state: latest_state,
302→        version,
303→    }))
