309→    State(state): State<CanonicalState>,
310→) -> Result<Json<EventListResponse>, (StatusCode, Json<serde_json::Value>)> {
311→    let session_id = SessionId::from_string(session_id);
312→    let branch = query
313→        .branch
314→        .as_deref()
315→        .map(BranchId::from_string)
316→        .unwrap_or_else(BranchId::main);
317→    let from_sequence = query.from_sequence.unwrap_or(1);
318→    let limit = query.limit.unwrap_or(256).min(10_000);
319→
320→    let events = state
321→        .runtime
322→        .read_events_on_branch(&session_id, &branch, from_sequence, limit)
323→        .await
324→        .map_err(internal_error)?;
325→
326→    Ok(Json(EventListResponse {
327→        session_id,
328→        branch,
329→        from_sequence,
330→        events,
331→    }))
332→}
