334→async fn stream_events(
335→    Path(session_id): Path<String>,
336→    Query(query): Query<StreamQuery>,
337→    State(state): State<CanonicalState>,
338→) -> Result<Response, (StatusCode, Json<serde_json::Value>)> {
339→    let session_id = SessionId::from_string(session_id);
340→    let format = StreamFormat::from_query(query.format.as_deref());
341→    let branch = query
342→        .branch
343→        .as_deref()
344→        .map(BranchId::from_string)
345→        .unwrap_or_else(BranchId::main);
346→    let cursor = query.cursor.unwrap_or(0);
347→    let replay_limit = query.replay_limit.unwrap_or(512).min(10_000);
348→
349→    let replay = state
350→        .runtime
351→        .read_events_on_branch(&session_id, &branch, cursor.saturating_add(1), replay_limit)
352→        .await
353→        .map_err(internal_error)?;
354→
355→    let mut subscription = state.runtime.subscribe_events();
356→    let (tx, rx) = mpsc::channel::<EventRecord>(256);
357→    let session_filter = session_id.clone();
358→    let branch_filter = branch.clone();
359→
360→    tokio::spawn(async move {
361→        for event in replay {
362→            let _ = tx.send(event).await;
363→        }
364→        while let Ok(event) = subscription.recv().await {
365→            if event.session_id == session_filter
366→                && event.branch_id == branch_filter
367→                && event.sequence > cursor
368→            {
369→                let _ = tx.send(event).await;
370→            }
371→        }
372→    });
373→
374→    let stream = ReceiverStream::new(rx).map(move |event| {
375→        let base = Event::default().id(event.sequence.to_string());
376→        let frame = match format {
377→            StreamFormat::Canonical => {
378→                let payload = serde_json::to_string(&event).unwrap_or_else(|_| "{}".to_owned());
379→                base.data(payload)
380→            }
381→            StreamFormat::VercelAiSdkV6 => {
382→                let payload =
383→                    serde_json::to_string(&json!({ "type": "data-aios-event", "data": event }))
384→                        .unwrap_or_else(|_| "{}".to_owned());
385→                base.data(payload)
386→            }
387→        };
388→        Ok::<Event, Infallible>(frame)
389→    });
390→
391→    let sse = Sse::new(stream).keep_alive(KeepAlive::new().interval(Duration::from_secs(15)));
392→    let mut response = sse.into_response();
393→    if format == StreamFormat::VercelAiSdkV6 {
394→        response.headers_mut().insert(
395→            "x-vercel-ai-ui-message-stream",
396→            "v1".parse().expect("static header value"),
397→        );
398→    }
399→    Ok(response)
400→}
401→
402→async fn create_branch(
403→    Path(session_id): Path<String>,
404→    State(state): State<CanonicalState>,
405→    Json(request): Json<CreateBranchRequest>,
406→) -> Result<Json<BranchInfo>, (StatusCode, Json<serde_json::Value>)> {
407→    let session_id = SessionId::from_string(session_id);
408→    let branch_id = BranchId::from_string(request.branch);
409→    let from_branch = request.from_branch.map(BranchId::from_string);
410→    let branch = state
411→        .runtime
412→        .create_branch(&session_id, branch_id, from_branch, request.fork_sequence)
413→        .await
414→        .map_err(internal_error)?;
415→    Ok(Json(branch))
416→}
417→
418→async fn list_branches(
419→    Path(session_id): Path<String>,
420→    State(state): State<CanonicalState>,
421→) -> Result<Json<BranchListResponse>, (StatusCode, Json<serde_json::Value>)> {
422→    let session_id = SessionId::from_string(session_id);
423→    let branches = state
424→        .runtime
425→        .list_branches(&session_id)
426→        .await
427→        .map_err(internal_error)?;
428→    Ok(Json(BranchListResponse {
429→        session_id,
430→        branches,
431→    }))
432→}
433→
434→async fn merge_branch(
435→    Path((session_id, branch_id)): Path<(String, String)>,
436→    State(state): State<CanonicalState>,
437→    Json(request): Json<MergeBranchRequest>,
438→) -> Result<Json<BranchMergeResponse>, (StatusCode, Json<serde_json::Value>)> {
439→    let session_id = SessionId::from_string(session_id);
440→    let source_branch = BranchId::from_string(branch_id);
441→    let target_branch = request
442→        .target_branch
443→        .map(BranchId::from_string)
444→        .unwrap_or_else(BranchId::main);
445→    let result = state
446→        .runtime
447→        .merge_branch(&session_id, source_branch, target_branch)
448→        .await
449→        .map_err(internal_error)?;
450→    Ok(Json(BranchMergeResponse { session_id, result }))
451→}
452→
453→async fn resolve_approval(
454→    Path((session_id, approval_id)): Path<(String, String)>,
455→    State(state): State<CanonicalState>,
456→    Json(request): Json<ResolveApprovalRequest>,
457→) -> Result<impl IntoResponse, (StatusCode, Json<serde_json::Value>)> {
458→    let session_id = SessionId::from_string(session_id);
459→    let parsed = Uuid::parse_str(&approval_id).map_err(bad_request)?;
460→    let actor = request.actor.unwrap_or_else(|| "api".to_owned());
461→
462→    state
463→        .runtime
464→        .resolve_approval(&session_id, parsed, request.approved, actor)
465→        .await
466→        .map_err(internal_error)?;
467→
468→    Ok((StatusCode::NO_CONTENT, Json(json!({}))))
469→}
470→
471→fn internal_error(error: impl std::fmt::Display) -> (StatusCode, Json<serde_json::Value>) {
472→    (
473→        StatusCode::INTERNAL_SERVER_ERROR,
474→        Json(json!({ "error": error.to_string() })),
475→    )
476→}
477→
478→fn bad_request(error: impl std::fmt::Display) -> (StatusCode, Json<serde_json::Value>) {
479→    (
480→        StatusCode::BAD_REQUEST,
481→        Json(json!({ "error": error.to_string() })),
482→    )
483→}
484→

