 592→    pub async fn create_branch(
 593→        &self,
 594→        session_id: &SessionId,
 595→        branch_id: BranchId,
 596→        from_branch: Option<BranchId>,
 597→        fork_sequence: Option<u64>,
 598→    ) -> Result<BranchInfo> {
 599→        let from_branch = from_branch.unwrap_or_else(BranchId::main);
 600→        let fork_sequence_value = {
 601→            let mut sessions = self.sessions.lock();
 602→            let session = sessions
 603→                .get_mut(session_id.as_str())
 604→                .with_context(|| format!("session not found: {session_id}"))?;
 605→            if session.branches.contains_key(&branch_id) {
 606→                bail!("branch already exists: {}", branch_id.as_str());
 607→            }
 608→            let parent = session
 609→                .branches
 610→                .get(&from_branch)
 611→                .with_context(|| format!("source branch not found: {}", from_branch.as_str()))?;
 612→            if let Some(target) = &parent.merged_into {
 613→                bail!(
 614→                    "source branch {} is merged into {} and is read-only",
 615→                    from_branch.as_str(),
 616→                    target.as_str()
 617→                );
 618→            }
 619→            let fork = fork_sequence.unwrap_or(parent.head_sequence);
 620→            if fork > parent.head_sequence {
 621→                bail!(
 622→                    "fork sequence {} exceeds source branch head {}",
 623→                    fork,
 624→                    parent.head_sequence
 625→                );
 626→            }
 627→
 628→            session.next_sequence_by_branch.insert(branch_id.clone(), 1);
 629→            session.branches.insert(
 630→                branch_id.clone(),
 631→                BranchRuntimeState {
 632→                    parent_branch: Some(from_branch.clone()),
 633→                    fork_sequence: fork,
 634→                    head_sequence: 0,
 635→                    merged_into: None,
 636→                },
 637→            );
 638→            fork
 639→        };
 640→
 641→        self.append_event(
 642→            session_id,
 643→            &branch_id,
 644→            EventKind::BranchCreated {
 645→                new_branch_id: branch_id.clone(),
 646→                fork_point_seq: fork_sequence_value,
 647→                name: branch_id.as_str().to_owned(),
 648→            },
 649→        )
 650→        .await?;
 651→        info!(
 652→            branch = %branch_id.as_str(),
 653→            from_branch = %from_branch.as_str(),
 654→            fork_sequence = fork_sequence_value,
 655→            "branch created"
 656→        );
 657→
 658→        self.branch_info(session_id, &branch_id)
 659→    }
