 690→    pub async fn merge_branch(
 691→        &self,
 692→        session_id: &SessionId,
 693→        source_branch: BranchId,
 694→        target_branch: BranchId,
 695→    ) -> Result<BranchMergeResult> {
 696→        if source_branch == target_branch {
 697→            bail!("source and target branch must differ");
 698→        }
 699→        if source_branch == BranchId::main() {
 700→            bail!("main branch cannot be used as a merge source");
 701→        }
 702→
 703→        let source_head =
 704→            {
 705→                let sessions = self.sessions.lock();
 706→                let session = sessions
 707→                    .get(session_id.as_str())
 708→                    .with_context(|| format!("session not found: {session_id}"))?;
 709→                let source = session.branches.get(&source_branch).with_context(|| {
 710→                    format!("source branch not found: {}", source_branch.as_str())
 711→                })?;
 712→                if let Some(merged_into) = &source.merged_into {
 713→                    bail!(
 714→                        "source branch {} already merged into {}",
 715→                        source_branch.as_str(),
 716→                        merged_into.as_str()
 717→                    );
 718→                }
 719→                let target = session.branches.get(&target_branch).with_context(|| {
 720→                    format!("target branch not found: {}", target_branch.as_str())
 721→                })?;
 722→                if let Some(merged_into) = &target.merged_into {
 723→                    bail!(
 724→                        "target branch {} is merged into {} and is read-only",
 725→                        target_branch.as_str(),
 726→                        merged_into.as_str()
 727→                    );
 728→                }
 729→                source.head_sequence
 730→            };
 731→
 732→        self.append_event(
 733→            session_id,
 734→            &target_branch,
 735→            EventKind::BranchMerged {
 736→                source_branch_id: source_branch.clone(),
 737→                merge_seq: source_head,
 738→            },
 739→        )
 740→        .await?;
 741→
 742→        let target_head = self.peek_last_sequence(session_id, &target_branch)?;
 743→        {
 744→            let mut sessions = self.sessions.lock();
 745→            let session = sessions
 746→                .get_mut(session_id.as_str())
 747→                .with_context(|| format!("session not found: {session_id}"))?;
 748→            let source = session
 749→                .branches
 750→                .get_mut(&source_branch)
 751→                .with_context(|| format!("source branch not found: {}", source_branch.as_str()))?;
 752→            source.merged_into = Some(target_branch.clone());
 753→        }
 754→        info!(
 755→            source_head_sequence = source_head,
 756→            target_head_sequence = target_head,
 757→            "branch merged"
 758→        );
 759→
 760→        Ok(BranchMergeResult {
 761→            source_branch,
 762→            target_branch,
 763→            source_head_sequence: source_head,
 764→            target_head_sequence: target_head,
 765→        })
 766→    }
