 861→    fn estimate_mode(&self, state: &AgentStateVector, pending_approvals: usize) -> OperatingMode {
 862→        if pending_approvals > 0 {
 863→            return OperatingMode::AskHuman;
 864→        }
 865→
 866→        if state.error_streak >= self.config.circuit_breaker_errors {
 867→            return OperatingMode::Recover;
 868→        }
 869→
 870→        if state.progress >= 0.98 {
 871→            return OperatingMode::Sleep;
 872→        }
 873→
 874→        if state.context_pressure > 0.8 || state.uncertainty > 0.65 {
 875→            return OperatingMode::Explore;
 876→        }
 877→
 878→        if state.side_effect_pressure > 0.6 {
 879→            return OperatingMode::Verify;
 880→        }
 881→
 882→        OperatingMode::Execute
 883→    }
