 885→    fn apply_homeostasis_controllers(
 886→        &self,
 887→        state: &mut AgentStateVector,
 888→        report: &ToolExecutionReport,
 889→    ) {
 890→        state.budget.tool_calls_remaining = state.budget.tool_calls_remaining.saturating_sub(1);
 891→        state.budget.tokens_remaining = state.budget.tokens_remaining.saturating_sub(750);
 892→        state.budget.time_remaining_ms = state.budget.time_remaining_ms.saturating_sub(1200);
 893→
 894→        if report.exit_status == 0 {
 895→            state.progress = (state.progress + 0.12).min(1.0);
 896→            state.uncertainty = (state.uncertainty * 0.85).max(0.05);
 897→            state.error_streak = 0;
 898→            state.side_effect_pressure = (state.side_effect_pressure + 0.2).min(1.0);
 899→        } else {
 900→            state.error_streak += 1;
 901→            state.uncertainty = (state.uncertainty + 0.18).min(1.0);
 902→            state.budget.error_budget_remaining =
 903→                state.budget.error_budget_remaining.saturating_sub(1);
 904→            state.side_effect_pressure = (state.side_effect_pressure * 0.5).max(0.1);
 905→        }
 906→
 907→        state.context_pressure = (state.context_pressure + 0.03).min(1.0);
 908→        state.human_dependency = if state.error_streak >= 2 { 0.6 } else { 0.0 };
 909→
 910→        state.risk_level = if state.uncertainty > 0.75 || state.side_effect_pressure > 0.7 {
 911→            RiskLevel::High
 912→        } else if state.uncertainty > 0.45 || state.side_effect_pressure > 0.4 {
 913→            RiskLevel::Medium
 914→        } else {
 915→            RiskLevel::Low
 916→        };
 917→    }
