 919→    async fn finalize_tick(
 920→        &self,
 921→        session_id: &SessionId,
 922→        branch_id: &BranchId,
 923→        manifest: &SessionManifest,
 924→        state: &mut AgentStateVector,
 925→        mode: &OperatingMode,
 926→    ) -> Result<u64> {
 927→        let mut emitted = 0_u64;
 928→
 929→        emitted += self
 930→            .emit_phase(session_id, branch_id, LoopPhase::Reflect)
 931→            .await?;
 932→
 933→        self.append_event(
 934→            session_id,
 935→            branch_id,
 936→            EventKind::BudgetUpdated {
 937→                budget: state.budget.clone(),
 938→                reason: "tick accounting".to_owned(),
 939→            },
 940→        )
 941→        .await?;
 942→        emitted += 1;
 943→
 944→        self.append_event(
 945→            session_id,
 946→            branch_id,
 947→            EventKind::StateEstimated {
 948→                state: state.clone(),
 949→                mode: *mode,
 950→            },
 951→        )
 952→        .await?;
 953→        emitted += 1;
 954→
 955→        let checkpoint_id = if self.should_checkpoint(session_id)? {
 956→            let checkpoint = self
 957→                .create_checkpoint(session_id, branch_id, manifest, state)
 958→                .await?;
 959→            self.append_event(
 960→                session_id,
 961→                branch_id,
 962→                EventKind::CheckpointCreated {
 963→                    checkpoint_id: checkpoint.checkpoint_id.clone(),
 964→                    event_sequence: checkpoint.event_sequence,
 965→                    state_hash: checkpoint.state_hash.clone(),
 966→                },
 967→            )
 968→            .await?;
 969→            emitted += 1;
 970→            Some(checkpoint.checkpoint_id)
 971→        } else {
 972→            None
 973→        };
 974→
 975→        self.write_heartbeat(session_id, state, mode).await?;
 976→        self.append_event(
 977→            session_id,
 978→            branch_id,
 979→            EventKind::Heartbeat {
 980→                summary: "tick complete".to_owned(),
 981→                checkpoint_id,
 982→            },
 983→        )
 984→        .await?;
 985→        emitted += 1;
 986→
 987→        emitted += self
 988→            .emit_phase(session_id, branch_id, LoopPhase::Sleep)
 989→            .await?;
 990→
 991→        self.persist_runtime_state(session_id, state.clone(), *mode)?;
 992→
 993→        Ok(emitted)
 994→    }
