1026→            EventKind::ToolCallCompleted {
1027→                tool_run_id: report.tool_run_id.clone(),
1028→                call_id: None,
1029→                tool_name: report.tool_name.clone(),
1030→                result: result_value,
1031→                duration_ms: 0,
1032→                status,
1033→            },
1034→        )
1035→        .await?;
1036→        emitted += 1;
1037→
1038→        if let ToolOutcome::Success { output } = &report.outcome
1039→            && let Some(path) = output.get("path").and_then(|v| v.as_str())
1040→        {
1041→            let full_path =
1042→                PathBuf::from(&manifest.workspace_root).join(path.trim_start_matches('/'));
1043→            let content_hash = if fs::try_exists(&full_path).await.unwrap_or(false) {
1044→                let data = fs::read(&full_path).await?;
1045→                sha256_bytes(&data)
1046→            } else {
1047→                "deleted".to_owned()
1048→            };
1049→
1050→            self.append_event(
1051→                session_id,
1052→                branch_id,
1053→                EventKind::FileMutated {
1054→                    path: path.to_owned(),
1055→                    content_hash,
1056→                },
1057→            )
1058→            .await?;
1059→            emitted += 1;
1060→        }
1061→
1062→        let run_dir = PathBuf::from(&manifest.workspace_root)
1063→            .join("tools")
1064→            .join("runs")
1065→            .join(report.tool_run_id.as_str());
1066→
1067→        fs::create_dir_all(&run_dir).await?;
1068→        self.write_pretty_json(run_dir.join("report.json"), report)
1069→            .await?;
1070→
1071→        let observation = extract_observation(&EventRecord::new(
1072→            session_id.clone(),
1073→            branch_id.clone(),
1074→            self.peek_last_sequence(session_id, branch_id)?,
1075→            EventKind::ToolCallCompleted {
1076→                tool_run_id: report.tool_run_id.clone(),
1077→                call_id: None,
1078→                tool_name: report.tool_name.clone(),
1079→                result: serde_json::to_value(&report.outcome).unwrap_or_default(),
1080→                duration_ms: 0,
1081→                status,
1082→            },
1083→        ));
1084→
1085→        if let Some(observation) = observation {
1086→            self.append_event(
1087→                session_id,
1088→                branch_id,
1089→                EventKind::Custom {
1090→                    event_type: "ObservationExtracted".to_owned(),
1091→                    data: serde_json::json!({
1092→                        "observation_id": observation.observation_id.to_string(),
1093→                    }),
1094→                },
1095→            )
1096→            .await?;
1097→            emitted += 1;
1098→        }
1099→
1100→        Ok(emitted)
1101→    }
