1103→    async fn emit_phase(
1104→        &self,
1105→        session_id: &SessionId,
1106→        branch_id: &BranchId,
1107→        phase: LoopPhase,
1108→    ) -> Result<u64> {
1109→        self.append_event(session_id, branch_id, EventKind::PhaseEntered { phase })
1110→            .await?;
