1114→    async fn append_event(
1115→        &self,
1116→        session_id: &SessionId,
1117→        branch_id: &BranchId,
1118→        kind: EventKind,
1119→    ) -> Result<()> {
1120→        let event_kind = event_kind_name(&kind);
1121→        let sequence = self.next_sequence(session_id, branch_id)?;
1122→        debug!(
1123→            session_id = %session_id,
1124→            branch = %branch_id.as_str(),
1125→            sequence,
1126→            event_kind,
1127→            "appending event"
1128→        );
1129→        let event = EventRecord::new(session_id.clone(), branch_id.clone(), sequence, kind);
1130→        let persisted = match self.event_store.append(event).await {
1131→            Ok(persisted) => persisted,
1132→            Err(append_error) => {
1133→                if let Err(resync_error) = self.resync_next_sequence(session_id, branch_id).await {
1134→                    warn!(
1135→                        session_id = %session_id,
1136→                        branch = %branch_id.as_str(),
1137→                        error = %append_error,
1138→                        resync_error = %resync_error,
1139→                        "event append failed and sequence resync failed"
1140→                    );
1141→                    return Err(anyhow::anyhow!(append_error.to_string())).context(format!(
1142→                        "failed appending event and failed sequence resync: {resync_error}"
1143→                    ));
1144→                }
1145→                warn!(
1146→                    session_id = %session_id,
1147→                    branch = %branch_id.as_str(),
1148→                    error = %append_error,
1149→                    "event append failed; sequence resynced"
1150→                );
1151→                return Err(anyhow::anyhow!(append_error.to_string()))
1152→                    .context("failed appending event; sequence was resynced");
1153→            }
1154→        };
1155→        let _ = self.stream.send(persisted.clone());
1156→        self.mark_branch_head(session_id, branch_id, persisted.sequence)?;
1157→        Ok(())
1158→    }
1159→
1160→    fn next_sequence(&self, session_id: &SessionId, branch_id: &BranchId) -> Result<u64> {
1161→        let mut sessions = self.sessions.lock();
1162→        let session = sessions
1163→            .get_mut(session_id.as_str())
1164→            .with_context(|| format!("session not found: {session_id}"))?;
1165→        if !session.branches.contains_key(branch_id) {
1166→            bail!("branch not found: {}", branch_id.as_str());
1167→        }
1168→        if let Some(merged_into) = session
1169→            .branches
1170→            .get(branch_id)
1171→            .and_then(|branch| branch.merged_into.as_ref())
1172→        {
1173→            bail!(
1174→                "branch {} is merged into {} and is read-only",
1175→                branch_id.as_str(),
1176→                merged_into.as_str()
1177→            );
1178→        }
1179→        let sequence = *session
1180→            .next_sequence_by_branch
1181→            .entry(branch_id.clone())
1182→            .or_insert(1);
1183→        session
1184→            .next_sequence_by_branch
1185→            .insert(branch_id.clone(), sequence.saturating_add(1));
1186→        Ok(sequence)
1187→    }
1188→
1189→    fn peek_last_sequence(&self, session_id: &SessionId, branch_id: &BranchId) -> Result<u64> {
1190→        let sessions = self.sessions.lock();
1191→        let session = sessions
1192→            .get(session_id.as_str())
1193→            .with_context(|| format!("session not found: {session_id}"))?;
1194→        if !session.branches.contains_key(branch_id) {
1195→            bail!("branch not found: {}", branch_id.as_str());
1196→        }
1197→        Ok(session
1198→            .next_sequence_by_branch
1199→            .get(branch_id)
1200→            .copied()
1201→            .unwrap_or(1)
1202→            .saturating_sub(1))
1203→    }
1204→
1205→    async fn resync_next_sequence(
1206→        &self,
1207→        session_id: &SessionId,
1208→        branch_id: &BranchId,
1209→    ) -> Result<()> {
1210→        let latest = self
1211→            .event_store
1212→            .head(session_id.clone(), branch_id.clone())
1213→            .await
1214→            .map_err(|error| anyhow::anyhow!(error.to_string()))
1215→            .context("failed loading latest sequence for resync")?;
1216→        let mut sessions = self.sessions.lock();
1217→        let session = sessions
1218→            .get_mut(session_id.as_str())
1219→            .with_context(|| format!("session not found: {session_id}"))?;
1220→        if !session.branches.contains_key(branch_id) {
1221→            bail!("branch not found: {}", branch_id.as_str());
1222→        }
1223→        session
1224→            .next_sequence_by_branch
1225→            .insert(branch_id.clone(), latest.saturating_add(1));
1226→        Ok(())
1227→    }
