1229→    fn mark_branch_head(
1230→        &self,
1231→        session_id: &SessionId,
1232→        branch_id: &BranchId,
1233→        sequence: u64,
1234→    ) -> Result<()> {
1235→        let mut sessions = self.sessions.lock();
1236→        let session = sessions
1237→            .get_mut(session_id.as_str())
1238→            .with_context(|| format!("session not found: {session_id}"))?;
1239→        let branch = session
1240→            .branches
1241→            .get_mut(branch_id)
1242→            .with_context(|| format!("branch not found: {}", branch_id.as_str()))?;
1243→        branch.head_sequence = branch.head_sequence.max(sequence);
1244→        Ok(())
1245→    }
