1247→    fn branch_info(&self, session_id: &SessionId, branch_id: &BranchId) -> Result<BranchInfo> {
1248→        let sessions = self.sessions.lock();
1249→        let session = sessions
1250→            .get(session_id.as_str())
1251→            .with_context(|| format!("session not found: {session_id}"))?;
