1253→            .branches
1254→            .get(branch_id)
1255→            .with_context(|| format!("branch not found: {}", branch_id.as_str()))?;
1256→        Ok(BranchInfo {
1257→            branch_id: branch_id.clone(),
1258→            parent_branch: state.parent_branch.clone(),
1259→            fork_sequence: state.fork_sequence,
1260→            head_sequence: state.head_sequence,
