1507→        EventKind::ApprovalRequested { .. } => "approval_requested",
1508→        EventKind::ApprovalResolved { .. } => "approval_resolved",
1509→        EventKind::ToolCallRequested { .. } => "tool_call_requested",
1510→        EventKind::ToolCallStarted { .. } => "tool_call_started",
1511→        EventKind::ToolCallCompleted { .. } => "tool_call_completed",
1512→        EventKind::VoiceSessionStarted { .. } => "voice_session_started",
1513→        EventKind::VoiceInputChunk { .. } => "voice_input_chunk",
1514→        EventKind::VoiceOutputChunk { .. } => "voice_output_chunk",
1515→        EventKind::VoiceSessionStopped { .. } => "voice_session_stopped",
1516→        EventKind::VoiceAdapterError { .. } => "voice_adapter_error",
1517→        EventKind::FileMutated { .. } => "file_mutated",
1518→        EventKind::Heartbeat { .. } => "heartbeat",
1519→        EventKind::CheckpointCreated { .. } => "checkpoint_created",
1520→        EventKind::StateEstimated { .. } => "state_estimated",
1521→        EventKind::BudgetUpdated { .. } => "budget_updated",
1522→        EventKind::CircuitBreakerTripped { .. } => "circuit_breaker_tripped",
