 79→
 80→        tracing::info!(
 81→            diff_count = diffs.len(),
 82→            "LakeFsObserver: workspace changed, emitting events"
 83→        );
 84→
 85→        for diff in diffs {
 86→            let payload = match diff {
 87→                DiffEntry::Added { path, entry } => EventPayload::FileWrite {
 88→                    path,
 89→                    blob_hash: entry.blob_hash.into(),
 90→                    size_bytes: entry.size_bytes,
 91→                    content_type: entry.content_type,
 92→                },
 93→                DiffEntry::Modified {
 94→                    path, new: entry, ..
 95→                } => EventPayload::FileWrite {
 96→                    path,
 97→                    blob_hash: entry.blob_hash.into(),
 98→                    size_bytes: entry.size_bytes,
 99→                    content_type: entry.content_type,
100→                },
101→                DiffEntry::Removed { path, .. } => EventPayload::FileDelete { path },
102→            };
103→
104→            let envelope = EventEnvelope {
105→                event_id: EventId::new(),
106→                session_id: sess_id.clone(),
107→                branch_id: branch_id.clone(),
108→                run_id: None,
109→                seq: 0,
110→                timestamp: EventEnvelope::now_micros(),
111→                parent_id: None,
112→                payload,
113→                metadata: std::collections::HashMap::new(),
114→                schema_version: 1,
115→            };
116→
117→            if let Err(e) = self.journal.append(envelope).await {
118→                tracing::warn!(%e, "LakeFsObserver: failed to append event");
119→            }
120→        }
121→    }
122→}
