124→#[derive(Parser)]
125→#[command(
126→    name = "arcan",
127→    about = "Arcan agent runtime with streaming and tool execution"
128→)]
129→struct Cli {
130→    #[command(subcommand)]
131→    command: Option<Command>,
132→
133→    /// Data directory for journal and blob storage
134→    #[arg(long, default_value = ".arcan", global = true)]
135→    data_dir: PathBuf,
136→
137→    /// HTTP listen port
138→    #[arg(long, default_value_t = 3000, global = true)]
139→    port: u16,
140→}
141→
142→#[derive(Subcommand)]
143→enum Command {
144→    /// Run the daemon in foreground
145→    Serve {
146→        /// Maximum orchestrator iterations per run
147→        #[arg(long, default_value_t = 10)]
148→        max_iterations: u32,
149→
150→        /// Approval timeout in seconds (default 300 = 5 minutes)
151→        #[arg(long, default_value_t = 300)]
152→        approval_timeout: u64,
153→    },
154→    /// Launch the TUI client (auto-starts daemon if needed)
155→    Chat {
156→        /// Session ID to attach to (defaults to most recent session)
157→        #[arg(short, long)]
158→        session: Option<String>,
159→
160→        /// Daemon URL (skip auto-start, connect to existing)
161→        #[arg(long)]
162→        url: Option<String>,
163→    },
164→    /// Send a single message and print the response (non-interactive)
165→    Run {
166→        /// The message to send
167→        message: String,
168→
169→        /// Session ID (created if it doesn't exist)
170→        #[arg(short, long)]
171→        session: Option<String>,
172→
173→        /// Daemon URL (skip auto-start, connect to existing)
174→        #[arg(long)]
175→        url: Option<String>,
176→
177→        /// Output raw JSON events (one per line) instead of formatted text
178→        #[arg(long)]
179→        json: bool,
