183→async fn shutdown_signal() {
184→    let ctrl_c = tokio::signal::ctrl_c();
185→
186→    #[cfg(unix)]
187→    {
188→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
189→            .expect("failed to install SIGTERM handler");
190→        tokio::select! {
191→            _ = ctrl_c => {},
192→            _ = sigterm.recv() => {},
193→        }
194→    }
195→
196→    #[cfg(not(unix))]
197→    {
198→        ctrl_c.await.ok();
199→    }
200→
201→    tracing::info!("Received shutdown signal, draining connections...");
202→}
