204→fn resolve_data_dir(data_dir: &PathBuf) -> anyhow::Result<PathBuf> {
205→    let workspace_root = std::env::current_dir()?;
206→    Ok(if data_dir.is_relative() {
207→        workspace_root.join(data_dir)
208→    } else {
209→        data_dir.clone()
210→    })
211→}
212→
213→fn read_last_session_hint(data_dir: &Path) -> Option<String> {
214→    let path = data_dir.join("last_session");
215→    let raw = std::fs::read_to_string(path).ok()?;
216→    let session = raw.trim();
217→    if session.is_empty() {
218→        None
219→    } else {
220→        Some(session.to_owned())
221→    }
222→}
223→
224→fn persist_last_session_hint(data_dir: &Path, session: &str) -> anyhow::Result<()> {
225→    std::fs::create_dir_all(data_dir)?;
226→    std::fs::write(data_dir.join("last_session"), session)?;
227→    Ok(())
228→}
229→
230→/// Resolve session via the daemon's HTTP API first, falling back to local hints.
231→/// This avoids opening the journal (which would conflict with the daemon's redb lock).
232→async fn resolve_session(
233→    data_dir: &Path,
234→    requested: Option<String>,
235→    base_url: Option<&str>,
236→) -> String {
237→    if let Some(session) = requested {
238→        return session;
239→    }
240→
241→    if let Some(session) = read_last_session_hint(data_dir) {
242→        return session;
243→    }
244→
245→    // Try the HTTP API if a daemon URL is available (avoids redb lock conflict).
246→    if let Some(url) = base_url {
247→        if let Some(session) = cli_run::resolve_session_via_api(url).await {
248→            return session;
249→        }
250→    }
251→
252→    "default".to_owned()
253→}
254→
255→fn run_serve(
256→    data_dir: &Path,
257→    port: u16,
258→    _max_iterations: u32,
259→    _approval_timeout: u64,
260→) -> anyhow::Result<()> {
261→    let workspace_root = std::env::current_dir()?;
262→
263→    // --- Lago persistence ---
264→    let journal_path = data_dir.join("journal.redb");
265→    let blobs_path = data_dir.join("blobs");
266→    std::fs::create_dir_all(&blobs_path)?;
267→
268→    tracing::info!(
269→        workspace = %workspace_root.display(),
270→        journal = %journal_path.display(),
271→        blobs = %blobs_path.display(),
272→        "Starting arcan"
273→    );
274→
275→    let journal = RedbJournal::open(&journal_path)?;
276→    let _blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
277→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
278→
279→    // --- Policies ---
280→    let fs_policy = FsPolicy::new(workspace_root.clone());
281→    let sandbox_policy = SandboxPolicy {
282→        workspace_root: workspace_root.clone(),
283→        shell_enabled: true,
284→        network: NetworkPolicy::AllowAll,
285→        allowed_env: BTreeSet::new(),
286→        max_execution_ms: 10_000,
287→        max_stdout_bytes: 1024 * 1024,
288→        max_stderr_bytes: 1024 * 1024,
289→        max_processes: 10,
290→        max_memory_mb: 512,
291→    };
292→
293→    // --- Tools ---
294→    let mut registry = ToolRegistry::default();
295→    registry.register(ReadFileTool::new(fs_policy.clone()));
296→    registry.register(WriteFileTool::new(fs_policy.clone()));
297→    registry.register(ListDirTool::new(fs_policy.clone()));
298→    registry.register(EditFileTool::new(fs_policy.clone()));
299→    registry.register(GlobTool::new(fs_policy.clone()));
300→    registry.register(GrepTool::new(fs_policy));
301→
302→    let runner = Box::new(LocalCommandRunner);
303→    registry.register(BashTool::new(sandbox_policy, runner));
304→
305→    let memory_dir = data_dir.join("memory");
306→    std::fs::create_dir_all(&memory_dir)?;
307→    registry.register(ReadMemoryTool::new(memory_dir.clone()));
308→    registry.register(WriteMemoryTool::new(memory_dir));
309→
310→    // --- Governed memory tools (event-sourced via Lago) ---
311→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
312→    registry.register(MemoryQueryTool::new(memory_projection));
313→    registry.register(MemoryProposeTool::new(journal.clone()));
314→    registry.register(MemoryCommitTool::new(journal.clone()));
315→
316→    // --- Provider ---
317→    // Selection order: ARCAN_PROVIDER env var > auto-detect from API keys > MockProvider
318→    let provider_name = std::env::var("ARCAN_PROVIDER").unwrap_or_default();
319→    let provider: Arc<dyn Provider> = match provider_name.as_str() {
320→        "mock" => {
321→            tracing::warn!("Provider: MockProvider (forced via ARCAN_PROVIDER=mock)");
322→            Arc::new(MockProvider)
323→        }
324→        "openai" => match arcan_provider::openai::OpenAiConfig::openai_from_env() {
325→            Ok(config) => {
326→                tracing::info!(model = %config.model, "Provider: OpenAI");
327→                Arc::new(arcan_provider::openai::OpenAiCompatibleProvider::new(
328→                    config,
329→                ))
330→            }
331→            Err(e) => {
332→                tracing::error!("ARCAN_PROVIDER=openai but config failed: {e}");
333→                return Err(e.into());
334→            }
335→        },
336→        "ollama" => match arcan_provider::openai::OpenAiConfig::ollama_from_env() {
337→            Ok(config) => {
338→                tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
339→                Arc::new(arcan_provider::openai::OpenAiCompatibleProvider::new(
340→                    config,
341→                ))
342→            }
343→            Err(e) => {
344→                tracing::error!("ARCAN_PROVIDER=ollama but config failed: {e}");
345→                return Err(e.into());
346→            }
347→        },
348→        "anthropic" => match AnthropicConfig::from_env() {
349→            Ok(config) => {
350→                tracing::info!(model = %config.model, "Provider: Anthropic");
351→                Arc::new(AnthropicProvider::new(config))
352→            }
353→            Err(e) => {
354→                tracing::error!("ARCAN_PROVIDER=anthropic but config failed: {e}");
355→                return Err(e.into());
356→            }
357→        },
358→        // Auto-detect: try providers in order
359→        _ => {
360→            if let Ok(config) = AnthropicConfig::from_env() {
361→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
362→                Arc::new(AnthropicProvider::new(config))
363→            } else if let Ok(config) = arcan_provider::openai::OpenAiConfig::openai_from_env() {
364→                tracing::info!(model = %config.model, "Provider: OpenAI (auto-detected)");
365→                Arc::new(arcan_provider::openai::OpenAiCompatibleProvider::new(
366→                    config,
367→                ))
368→            } else {
369→                tracing::warn!(
370→                    "Provider: MockProvider (set ARCAN_PROVIDER or API key env vars for real LLM)"
371→                );
372→                Arc::new(MockProvider)
373→            }
374→        }
375→    };
376→
377→    // --- Canonical aiOS runtime adapters ---
378→    let event_store: Arc<dyn EventStorePort> =
379→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
380→    let provider_adapter: Arc<dyn ModelProviderPort> =
381→        Arc::new(ArcanProviderAdapter::new(provider, registry.definitions()));
382→    let observer = Arc::new(LakeFsObserver {
383→        workspace_root: workspace_root.clone(),
384→        journal: journal.clone(),
385→        blob_store: _blob_store,
386→    });
387→    let tool_harness: Arc<dyn ToolHarnessPort> =
388→        Arc::new(ArcanHarnessAdapter::new(registry).with_observer(observer));
389→    let policy_gate: Arc<dyn PolicyGatePort> =
390→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
391→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
392→
393→    let runtime = Arc::new(KernelRuntime::new(
394→        RuntimeConfig::new(data_dir.to_path_buf()),
395→        event_store,
396→        provider_adapter,
397→        tool_harness,
398→        approvals,
399→        policy_gate,
400→    ));
401→
402→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
403→    let data_dir_owned = data_dir.to_path_buf();
404→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
405→        .enable_all()
406→        .build()?;
407→
408→    tokio_runtime.block_on(async move {
409→        // --- HTTP Server ---
410→        let router = create_canonical_router(runtime);
411→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
412→        let listener = TcpListener::bind(addr).await?;
413→
414→        tracing::info!(%addr, "Listening");
415→        axum::serve(listener, router)
416→            .with_graceful_shutdown(shutdown_signal())
417→            .await?;
418→
419→        // Clean up PID file on graceful shutdown.
420→        daemon::remove_pid_file(&data_dir_owned);
421→
422→        tracing::info!("Server shut down gracefully");
423→        Ok(())
424→    })
425→}
426→
427→async fn run_chat(
428→    data_dir: PathBuf,
429→    port: u16,
430→    session: Option<String>,
431→    url: Option<String>,
432→) -> anyhow::Result<()> {
433→    // Ensure daemon is running first to avoid redb lock conflicts.
434→    let base_url = match url {
435→        Some(u) => u,
436→        None => daemon::ensure_daemon(&data_dir, port).await?,
437→    };
438→
439→    // Resolve session via API (no direct journal access).
440→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
441→    tracing::info!(session = %session, "launching TUI");
442→
443→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
444→        tracing::warn!(%error, "failed to persist last_session hint");
445→    }
446→
447→    arcan_tui::run_tui(base_url, session).await
448→}
449→
450→async fn run_message(
451→    data_dir: PathBuf,
452→    port: u16,
453→    message: String,
454→    session: Option<String>,
455→    url: Option<String>,
456→    json_output: bool,
457→) -> anyhow::Result<()> {
458→    // Ensure daemon is running first.
459→    let base_url = match url {
460→        Some(u) => u,
461→        None => daemon::ensure_daemon(&data_dir, port).await?,
462→    };
463→
464→    // Resolve session via API (no direct journal access).
465→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
466→
467→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
468→        tracing::warn!(%error, "failed to persist last_session hint");
469→    }
470→
471→    let exit_code = cli_run::run_cli(&base_url, &session, &message, json_output).await?;
472→    if exit_code != 0 {
473→        std::process::exit(exit_code);
474→    }
475→    Ok(())
476→}
477→
478→fn main() -> anyhow::Result<()> {
479→    let cli = Cli::parse();
480→    let data_dir = resolve_data_dir(&cli.data_dir)?;
481→
482→    match cli.command {
483→        Some(Command::Serve {
484→            max_iterations,
485→            approval_timeout,
486→        }) => {
487→            // Structured logging to stderr for daemon mode
488→            tracing_subscriber::fmt()
489→                .with_env_filter(EnvFilter::from_default_env())
490→                .init();
491→
492→            run_serve(&data_dir, cli.port, max_iterations, approval_timeout)
493→        }
494→        Some(Command::Chat { session, url }) => {
495→            // File-based logging for TUI mode (don't clobber the terminal)
496→            let log_dir = data_dir.join("logs");
497→            std::fs::create_dir_all(&log_dir)?;
498→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
499→            tracing_subscriber::fmt()
500→                .with_writer(file_appender)
501→                .with_env_filter(EnvFilter::from_default_env())
502→                .init();
503→
504→            let runtime = tokio::runtime::Builder::new_multi_thread()
505→                .enable_all()
506→                .build()?;
507→            runtime.block_on(run_chat(data_dir, cli.port, session, url))
508→        }
509→        Some(Command::Run {
510→            message,
511→            session,
512→            url,
513→            json,
514→        }) => {
515→            // File-based logging for CLI mode (don't clobber stdout)
516→            let log_dir = data_dir.join("logs");
517→            std::fs::create_dir_all(&log_dir)?;
518→            let file_appender = tracing_appender::rolling::never(&log_dir, "run.log");
519→            tracing_subscriber::fmt()
520→                .with_writer(file_appender)
521→                .with_env_filter(EnvFilter::from_default_env())
522→                .init();
523→
524→            let runtime = tokio::runtime::Builder::new_multi_thread()
525→                .enable_all()
526→                .build()?;
527→            runtime.block_on(run_message(data_dir, cli.port, message, session, url, json))
528→        }
529→        None => {
530→            // Default: launch TUI with auto-daemon (same as `arcan chat`)
531→            let log_dir = data_dir.join("logs");
532→            std::fs::create_dir_all(&log_dir)?;
533→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
534→            tracing_subscriber::fmt()
535→                .with_writer(file_appender)
536→                .with_env_filter(EnvFilter::from_default_env())
537→                .init();
538→
539→            let runtime = tokio::runtime::Builder::new_multi_thread()
540→                .enable_all()
541→                .build()?;
542→            runtime.block_on(run_chat(data_dir, cli.port, None, None))
543→        }
544→    }
545→}
