            CoreError::Provider("OPENAI_API_KEY environment variable not set".to_string())
        })?;

        let model = std::env::var("OPENAI_MODEL").unwrap_or_else(|_| "gpt-4o".to_string());
        let max_tokens = std::env::var("OPENAI_MAX_TOKENS")
            .ok()
