use std::sync::Arc;

use aios_protocol::{
    BranchId, EventKind, EventRecord, KernelError, ModelCompletion, ModelCompletionRequest,
    ModelDirective, ModelProviderPort, ModelStopReason, SessionId, TokenUsage, ToolCall,
};
use arcan_core::protocol::{
