184→async fn shutdown_signal() {
185→    let ctrl_c = tokio::signal::ctrl_c();
186→
187→    #[cfg(unix)]
188→    {
189→        let mut sigterm = tokio::signal::unix::signal(tokio::signal::unix::SignalKind::terminate())
190→            .expect("failed to install SIGTERM handler");
191→        tokio::select! {
192→            _ = ctrl_c => {},
193→            _ = sigterm.recv() => {},
194→        }
195→    }
196→
197→    #[cfg(not(unix))]
198→    {
199→        ctrl_c.await.ok();
200→    }
201→
202→    tracing::info!("Received shutdown signal, draining connections...");
203→}
