487→fn main() -> anyhow::Result<()> {
488→    let cli = Cli::parse();
489→    let data_dir = resolve_data_dir(&cli.data_dir)?;
490→
491→    match cli.command {
492→        Some(Command::Serve {
493→            max_iterations,
494→            approval_timeout,
495→        }) => {
496→            // Structured logging to stderr for daemon mode
497→            tracing_subscriber::fmt()
498→                .with_env_filter(EnvFilter::from_default_env())
499→                .init();
500→
501→            run_serve(&data_dir, cli.port, max_iterations, approval_timeout)
502→        }
503→        Some(Command::Chat { session, url }) => {
504→            // File-based logging for TUI mode (don't clobber the terminal)
505→            let log_dir = data_dir.join("logs");
506→            std::fs::create_dir_all(&log_dir)?;
507→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
508→            tracing_subscriber::fmt()
509→                .with_writer(file_appender)
510→                .with_env_filter(EnvFilter::from_default_env())
511→                .init();
512→
513→            let runtime = tokio::runtime::Builder::new_multi_thread()
514→                .enable_all()
515→                .build()?;
516→            runtime.block_on(run_chat(data_dir, cli.port, session, url))
517→        }
518→        Some(Command::Run {
519→            message,
520→            session,
521→            url,
522→            json,
523→        }) => {
524→            // File-based logging for CLI mode (don't clobber stdout)
525→            let log_dir = data_dir.join("logs");
526→            std::fs::create_dir_all(&log_dir)?;
527→            let file_appender = tracing_appender::rolling::never(&log_dir, "run.log");
528→            tracing_subscriber::fmt()
529→                .with_writer(file_appender)
530→                .with_env_filter(EnvFilter::from_default_env())
531→                .init();
532→
533→            let runtime = tokio::runtime::Builder::new_multi_thread()
534→                .enable_all()
535→                .build()?;
536→            runtime.block_on(run_message(data_dir, cli.port, message, session, url, json))
537→        }
538→        None => {
539→            // Default: launch TUI with auto-daemon (same as `arcan chat`)
540→            let log_dir = data_dir.join("logs");
541→            std::fs::create_dir_all(&log_dir)?;
542→            let file_appender = tracing_appender::rolling::never(&log_dir, "tui.log");
543→            tracing_subscriber::fmt()
544→                .with_writer(file_appender)
545→                .with_env_filter(EnvFilter::from_default_env())
546→                .init();
547→
548→            let runtime = tokio::runtime::Builder::new_multi_thread()
549→                .enable_all()
550→                .build()?;
551→            runtime.block_on(run_chat(data_dir, cli.port, None, None))
552→        }
553→    }
554→}
