221→/// Try to resolve a session via the daemon's HTTP API.
222→pub async fn resolve_session_via_api(base_url: &str) -> Option<String> {
223→    let client = Client::builder()
224→        .timeout(std::time::Duration::from_secs(2))
225→        .build()
226→        .ok()?;
227→
228→    let response = client
229→        .get(format!("{base_url}/sessions"))
230→        .send()
231→        .await
232→        .ok()?;
233→
234→    if !response.status().is_success() {
235→        return None;
236→    }
237→
238→    let sessions: Vec<serde_json::Value> = response.json().await.ok()?;
239→    sessions
240→        .first()
241→        .and_then(|s| s.get("session_id"))
242→        .and_then(|v| v.as_str())
243→        .map(String::from)
244→}
