  1→//! Compound key encoding and decoding for redb tables.
  2→//!
  3→//! ULID strings are exactly 26 characters. We store them as fixed-width
  4→//! 26-byte UTF-8 slices so that lexicographic byte ordering on the compound
  5→//! key groups events by (session, branch, seq) naturally.
  6→
  7→/// Width of a ULID string in bytes.
  8→const ID_WIDTH: usize = 26;
  9→
 10→/// Total width of an event compound key: session_id + branch_id + seq.
 11→pub const EVENT_KEY_LEN: usize = ID_WIDTH + ID_WIDTH + 8; // 60 bytes
 12→
 13→/// Total width of a branch compound key: session_id + branch_id.
 14→pub const BRANCH_KEY_LEN: usize = ID_WIDTH + ID_WIDTH; // 52 bytes
 15→
 16→// ---  Event key helpers
 17→
 18→/// Encode a compound event key: session_id (26B) || branch_id (26B) || seq (8B BE).
 19→///
 20→/// The session_id and branch_id are right-padded with spaces if shorter than
 21→/// 26 bytes (should not happen for valid ULIDs, but we handle it defensively).
 22→/// The sequence number is encoded in big-endian so that lexicographic ordering
 23→/// of the byte slice corresponds to numeric ordering.
 24→pub fn encode_event_key(session_id: &str, branch_id: &str, seq: u64) -> Vec<u8> {
 25→    let mut buf = vec![0u8; EVENT_KEY_LEN];
 26→    write_padded_id(&mut buf[..ID_WIDTH], session_id);
 27→    write_padded_id(&mut buf[ID_WIDTH..ID_WIDTH * 2], branch_id);
 28→    buf[ID_WIDTH * 2..].copy_from_slice(&seq.to_be_bytes());
 29→    buf
 30→}
 31→
 32→/// Decode a compound event key back into (session_id, branch_id, seq).
 33→///
 34→/// # Panics
 35→/// Panics if `bytes.len() != EVENT_KEY_LEN`.
 36→pub fn decode_event_key(bytes: &[u8]) -> (String, String, u64) {
 37→    assert_eq!(bytes.len(), EVENT_KEY_LEN, "invalid event key length");
 38→    let session_id = read_padded_id(&bytes[..ID_WIDTH]);
 39→    let branch_id = read_padded_id(&bytes[ID_WIDTH..ID_WIDTH * 2]);
 40→    let seq = u64::from_be_bytes(bytes[ID_WIDTH * 2..].try_into().unwrap());
 41→    (session_id, branch_id, seq)
 42→}
 43→
 44→// ---  Branch key helpers
 45→
 46→/// Encode a compound branch key: session_id (26B) || branch_id (26B).
 47→pub fn encode_branch_key(session_id: &str, branch_id: &str) -> Vec<u8> {
 48→    let mut buf = vec![0u8; BRANCH_KEY_LEN];
 49→    write_padded_id(&mut buf[..ID_WIDTH], session_id);
 50→    write_padded_id(&mut buf[ID_WIDTH..], branch_id);
 51→    buf
 52→}
 53→
 54→/// Decode a compound branch key back into (session_id, branch_id).
 55→///
 56→/// # Panics
 57→/// Panics if `bytes.len() != BRANCH_KEY_LEN`.
 58→pub fn decode_branch_key(bytes: &[u8]) -> (String, String) {
 59→    assert_eq!(bytes.len(), BRANCH_KEY_LEN, "invalid branch key length");
 60→    let session_id = read_padded_id(&bytes[..ID_WIDTH]);
 61→    let branch_id = read_padded_id(&bytes[ID_WIDTH..]);
 62→    (session_id, branch_id)
 63→}
 64→
 65→// ---  Internal helpers
 66→
 67→/// Write an ID string into a fixed-width buffer, padding with spaces on the right.
 68→fn write_padded_id(buf: &mut [u8], id: &str) {
 69→    let id_bytes = id.as_bytes();
 70→    let copy_len = id_bytes.len().min(buf.len());
 71→    buf[..copy_len].copy_from_slice(&id_bytes[..copy_len]);
 72→    // Pad remaining bytes with spaces (0x20) for consistent ordering
 73→    for byte in &mut buf[copy_len..] {
 74→        *byte = b' ';
 75→    }
 76→}
 77→
 78→/// Read a padded ID from a fixed-width buffer, trimming trailing spaces.
 79→fn read_padded_id(buf: &[u8]) -> String {
 80→    let s = std::str::from_utf8(buf).unwrap_or("");
 81→    s.trim_end_matches(' ').to_string()
 82→}
