146→    #[test]
147→    fn short_id_gets_padded() {
148→        let key = encode_event_key("short", "also_short", 0);
149→        let (s, b, n) = decode_event_key(&key);
150→        assert_eq!(s, "short");
151→        assert_eq!(b, "also_short");
152→        assert_eq!(n, 0);
153→    }
