  1→use std::fs;
  2→use std::path::Path;
  3→use std::time::Duration;
  4→
  5→/// Check whether a daemon is already healthy at the given URL.
  6→async fn is_daemon_healthy(base_url: &str) -> bool {
  7→    let url = format!("{base_url}/health");
  8→    let client = reqwest::Client::builder()
  9→        .timeout(Duration::from_secs(2))
 10→        .build();
 11→    let Ok(client) = client else { return false };
 12→    matches!(client.get(&url).send().await, Ok(resp) if resp.status().is_success())
 13→}
 14→
 15→/// Check if a PID file exists and the process is alive.
 16→/// Returns `Some(pid)` if alive, `None` if dead or no PID file.
 17→fn check_existing_pid(data_dir: &Path) -> Option<u32> {
 18→    let pid_path = data_dir.join("daemon.pid");
 19→    let raw = fs::read_to_string(&pid_path).ok()?;
 20→    let pid: u32 = raw.trim().parse().ok()?;
 21→
 22→    if is_process_alive(pid) {
 23→        Some(pid)
 24→    } else {
 25→        tracing::warn!(pid, "Stale daemon.pid found (process dead), removing");
 26→        let _ = fs::remove_file(&pid_path);
 27→        None
 28→    }
 29→}
 30→
 31→/// Check if a process with the given PID is alive using `kill -0`.
 32→#[cfg(unix)]
 33→fn is_process_alive(pid: u32) -> bool {
 34→    std::process::Command::new("kill")
 35→        .args(["-0", &pid.to_string()])
 36→        .stdout(std::process::Stdio::null())
 37→        .stderr(std::process::Stdio::null())
 38→        .status()
 39→        .is_ok_and(|s| s.success())
 40→}
 41→
 42→#[cfg(not(unix))]
 43→fn is_process_alive(_pid: u32) -> bool {
 44→    // On non-Unix, we can't cheaply check — assume alive if PID file exists.
 45→    true
 46→}
 47→
 48→/// Remove the daemon.pid file (called on graceful shutdown).
 49→pub fn remove_pid_file(data_dir: &Path) {
 50→    let pid_path = data_dir.join("daemon.pid");
 51→    if pid_path.exists() {
 52→        let _ = fs::remove_file(&pid_path);
 53→        tracing::info!("Removed daemon.pid");
 54→    }
 55→}
 56→
 57→/// Ensure a daemon is running on the given port.
 58→///
 59→/// 1. Probe `GET /health`. If healthy, return immediately.
 60→/// 2. Check `daemon.pid` — if process alive but health fails, wait briefly.
 61→/// 3. If PID is stale, remove PID file and proceed.
 62→/// 4. Spawn `arcan serve` as a detached child process.
 63→/// 5. Poll `/health` until it succeeds (up to ~12 s).
 64→pub async fn ensure_daemon(data_dir: &Path, port: u16) -> anyhow::Result<String> {
 65→    let base_url = format!("http://127.0.0.1:{port}");
 66→
 67→    if is_daemon_healthy(&base_url).await {
 68→        tracing::info!("Daemon already running on {base_url}");
 69→        return Ok(base_url);
 70→    }
 71→
 72→    // Check PID file before spawning a new daemon.
 73→    if let Some(pid) = check_existing_pid(data_dir) {
 74→        // Process is alive but health check failed — it might be starting up.
 75→        tracing::info!(pid, "Daemon process alive, waiting for health...");
 76→        let delay = Duration::from_millis(200);
 77→        for _ in 0..15 {
 78→            tokio::time::sleep(delay).await;
 79→            if is_daemon_healthy(&base_url).await {
 80→                tracing::info!("Existing daemon became healthy on {base_url}");
 81→                return Ok(base_url);
 82→            }
 83→        }
 84→        // Still not healthy after 3s — the process might be stuck.
 85→        tracing::warn!(
 86→            pid,
 87→            "Daemon process alive but not healthy after 3s, spawning new"
 88→        );
 89→    }
 90→
 91→    tracing::info!("Starting daemon on port {port}...");
 92→
 93→    fs::create_dir_all(data_dir)?;
 94→    let log_file = fs::File::create(data_dir.join("daemon.log"))?;
 95→    let stderr_log = log_file.try_clone()?;
 96→
 97→    // Resolve the current executable so `arcan serve` uses the same binary.
 98→    let exe = std::env::current_exe()?;
 99→
100→    let child = std::process::Command::new(exe)
101→        .args([
102→            "serve",
103→            "--port",
104→            &port.to_string(),
105→            "--data-dir",
106→            &data_dir.to_string_lossy(),
107→        ])
108→        .stdout(log_file)
109→        .stderr(stderr_log)
110→        .stdin(std::process::Stdio::null())
111→        .spawn()?;
112→
113→    // Write PID for later inspection / cleanup.
114→    fs::write(data_dir.join("daemon.pid"), child.id().to_string())?;
115→
116→    // Poll health endpoint.
117→    let max_retries = 60;
118→    let delay = Duration::from_millis(200);
119→    for i in 0..max_retries {
120→        tokio::time::sleep(delay).await;
121→        if is_daemon_healthy(&base_url).await {
122→            tracing::info!("Daemon healthy after {} ms", (i + 1) * 200);
123→            return Ok(base_url);
124→        }
125→    }
126→
127→    anyhow::bail!(
128→        "Daemon failed to become healthy within {}s. Check {}/daemon.log for details.",
129→        max_retries * 200 / 1000,
130→        data_dir.display()
131→    );
132→}
