 37→}
 38→
 39→#[async_trait::async_trait]
 40→impl arcan_aios_adapters::tools::ToolHarnessObserver for LakeFsObserver {
 41→    async fn post_execute(&self, session_id: String, _tool_name: String) {
 42→        // We skip memory tools since they don't modify the FS directly, and bash since we might want more granular control, but for now we trace everything.
 43→        let sess_id = SessionId::from_string(session_id.clone());
 44→        let branch_id = BranchId::from_string("main");
 45→
 46→        let events = match self
 47→            .journal
 48→            .read(EventQuery::new().session(lago_core::SessionId::from_string(session_id)))
 49→            .await
 50→        {
 51→            Ok(events) => events,
 52→            Err(e) => {
 53→                tracing::warn!(%e, "LakeFsObserver: failed to read journal");
 54→                return;
 55→            }
 56→        };
 57→
 58→        let mut proj = ManifestProjection::new();
 59→        for e in events {
 60→            if e.branch_id == branch_id {
 61→                let _ = proj.on_event(&e);
 62→            }
 63→        }
 64→
 65→        let current_manifest = proj.manifest().clone();
 66→
 67→        let new_manifest =
 68→            match lago_fs::snapshot(&self.workspace_root, &current_manifest, &self.blob_store) {
 69→                Ok(m) => m,
 70→                Err(e) => {
 71→                    tracing::warn!(%e, "LakeFsObserver: failed to snapshot workspace");
 72→                    return;
 73→                }
 74→            };
 75→
 76→        let diffs = lago_fs::diff(&current_manifest, &new_manifest);
 77→        if diffs.is_empty() {
 78→            return;
 79→        }
 80→
 81→        tracing::info!(
 82→            diff_count = diffs.len(),
 83→            "LakeFsObserver: workspace changed, emitting events"
 84→        );
 85→
 86→        for diff in diffs {
 87→            let payload = match diff {
 88→                DiffEntry::Added { path, entry } => EventPayload::FileWrite {
 89→                    path,
 90→                    blob_hash: entry.blob_hash.into(),
 91→                    size_bytes: entry.size_bytes,
 92→                    content_type: entry.content_type,
 93→                },
 94→                DiffEntry::Modified {
 95→                    path, new: entry, ..
 96→                } => EventPayload::FileWrite {
 97→                    path,
 98→                    blob_hash: entry.blob_hash.into(),
 99→                    size_bytes: entry.size_bytes,
100→                    content_type: entry.content_type,
101→                },
102→                DiffEntry::Removed { path, .. } => EventPayload::FileDelete { path },
103→            };
104→
105→            let envelope = EventEnvelope {
106→                event_id: EventId::new(),
107→                session_id: sess_id.clone(),
108→                branch_id: branch_id.clone(),
109→                run_id: None,
110→                seq: 0,
111→                timestamp: EventEnvelope::now_micros(),
112→                parent_id: None,
113→                payload,
114→                metadata: std::collections::HashMap::new(),
115→                schema_version: 1,
116→            };
117→
118→            if let Err(e) = self.journal.append(envelope).await {
119→                tracing::warn!(%e, "LakeFsObserver: failed to append event");
120→            }
121→        }
122→    }
123→}
