  9→/// A lago [`Projection`] that replays arcan events to rebuild
 10→/// `AppState` and `Vec<ChatMessage>` (conversation history).
 11→///
 12→/// This replaces the ad-hoc replay logic in `loop.rs` with a
 13→/// reusable, testable projection.
 14→pub struct AppStateProjection {
 15→    state: AppState,
 16→    messages: Vec<ChatMessage>,
 17→}
 18→
 19→impl AppStateProjection {
 20→    pub fn new() -> Self {
 21→        Self {
 22→            state: AppState::default(),
 23→            messages: Vec::new(),
 24→        }
 25→    }
 26→
 27→    /// Return the reconstructed `AppState`.
 28→    pub fn state(&self) -> &AppState {
 29→        &self.state
 30→    }
 31→
 32→    /// Return the reconstructed conversation history.
 33→    pub fn messages(&self) -> &[ChatMessage] {
 34→        &self.messages
 35→    }
 36→
 37→    /// Consume the projection and return the state + messages.
 38→    pub fn into_parts(self) -> (AppState, Vec<ChatMessage>) {
 39→        (self.state, self.messages)
 40→    }
 41→}
 42→
 43→impl Default for AppStateProjection {
 44→    fn default() -> Self {
 45→        Self::new()
 46→    }
 47→}
 48→
 49→impl Projection for AppStateProjection {
 50→    fn on_event(&mut self, envelope: &EventEnvelope) -> LagoResult<()> {
 51→        let Some(agent_event) = event_map::lago_to_arcan(envelope) else {
 52→            return Ok(());
 53→        };
 54→
 55→        match agent_event {
 56→            AgentEvent::StatePatched { patch, .. } => {
 57→                let _ = self.state.apply_patch(&patch);
 58→            }
 59→            AgentEvent::TextDelta { delta, .. } => {
 60→                // Aggregate deltas into the last assistant message.
 61→                if let Some(last) = self.messages.last_mut() {
 62→                    if last.role == Role::Assistant {
 63→                        last.content.push_str(&delta);
 64→                    } else {
 65→                        self.messages.push(ChatMessage::assistant(delta));
 66→                    }
 67→                } else {
 68→                    self.messages.push(ChatMessage::assistant(delta));
 69→                }
 70→            }
 71→            AgentEvent::ToolCallCompleted { result, .. } => {
 72→                let output_str =
 73→                    serde_json::to_string(&result.output).unwrap_or_else(|_| "{}".to_string());
 74→                self.messages
 75→                    .push(ChatMessage::tool_result(&result.call_id, output_str));
 76→            }
 77→            _ => {}
 78→        }
 79→
 80→        Ok(())
 81→    }
 82→
 83→    fn name(&self) -> &str {
 84→        "arcan::app_state"
 85→    }
 86→}
