  3→/// The kind of context block, determining assembly order and default priority.
  4→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
  5→pub enum ContextBlockKind {
  6→    Persona,
  7→    Rules,
  8→    Memory,
  9→    Retrieval,
 10→    Workspace,
 11→    Task,
 12→}
 13→
 14→impl ContextBlockKind {
 15→    /// Fixed assembly order index: Persona=0, Rules=1, Memory=2, Retrieval=3, Workspace=4, Task=5
 16→    fn order(self) -> u8 {
 17→        match self {
 18→            Self::Persona => 0,
 19→            Self::Rules => 1,
 20→            Self::Memory => 2,
 21→            Self::Retrieval => 3,
 22→            Self::Workspace => 4,
 23→            Self::Task => 5,
 24→        }
 25→    }
 26→}
 27→
 28→/// A typed block of context to be assembled into the system prompt.
 29→#[derive(Debug, Clone)]
 30→pub struct ContextBlock {
 31→    pub kind: ContextBlockKind,
 32→    pub content: String,
 33→    /// Priority (0 = lowest, 255 = highest). Higher priority blocks are kept when budget is exceeded.
 34→    /// Persona defaults to 255 (never dropped).
 35→    pub priority: u8,
 36→}
 37→
 38→/// Configuration for the context compiler.
 39→#[derive(Debug, Clone)]
 40→pub struct ContextCompilerConfig {
 41→    /// Total token budget for compiled system messages.
 42→    pub total_budget: usize,
 43→    /// Per-kind token budgets. Blocks are truncated to their kind's budget.
 44→    /// Kinds not listed here get unlimited (up to total_budget).
 45→    pub block_budgets: Vec<(ContextBlockKind, usize)>,
 46→}
 47→
 48→impl Default for ContextCompilerConfig {
 49→    fn default() -> Self {
 50→        Self {
 51→            total_budget: 30_000,
 52→            block_budgets: vec![
 53→                (ContextBlockKind::Persona, 2_000),
 54→                (ContextBlockKind::Rules, 5_000),
 55→                (ContextBlockKind::Memory, 8_000),
 56→                (ContextBlockKind::Retrieval, 6_000),
 57→                (ContextBlockKind::Workspace, 5_000),
 58→                (ContextBlockKind::Task, 4_000),
 59→            ],
 60→        }
 61→    }
 62→}
 63→
 64→impl ContextCompilerConfig {
 65→    fn budget_for(&self, kind: ContextBlockKind) -> Option<usize> {
 66→        self.block_budgets
 67→            .iter()
 68→            .find(|(k, _)| *k == kind)
 69→            .map(|(_, b)| *b)
 70→    }
 71→}
 72→
 73→/// Result of context compilation.
 74→#[derive(Debug, Clone)]
 75→pub struct CompiledContext {
 76→    /// System messages to prepend to the conversation.
 77→    pub system_messages: Vec<ChatMessage>,
 78→    /// Estimated total tokens used.
 79→    pub total_tokens: usize,
 80→    /// Blocks that were dropped due to budget constraints.
 81→    pub dropped_blocks: Vec<ContextBlockKind>,
 82→}
 83→
 84→/// Estimate token count using ~4 chars per token heuristic.
 85→fn estimate_tokens(text: &str) -> usize {
 86→    text.len().div_ceil(4).max(1)
 87→}
 88→
 89→/// Truncate text to approximately `max_tokens` tokens, respecting word boundaries.
 90→fn truncate_to_budget(text: &str, max_tokens: usize) -> &str {
 91→    let max_chars = max_tokens * 4;
 92→    if text.len() <= max_chars {
 93→        return text;
 94→    }
 95→    // Find the last space before max_chars for word boundary
 96→    let truncated = &text[..max_chars];
 97→    match truncated.rfind(' ') {
 98→        Some(pos) if pos > max_chars / 2 => &text[..pos],
 99→        _ => truncated,
100→    }
101→}
102→
103→/// Compile context blocks into system messages with budget enforcement.
104→///
105→/// Assembly order is fixed: Persona -> Rules -> Memory -> Retrieval -> Workspace -> Task.
106→/// Each block is truncated to its per-kind budget, then if total exceeds the total budget,
107→/// lowest-priority blocks are dropped (Persona is never dropped).
108→pub fn compile_context(blocks: &[ContextBlock], config: &ContextCompilerConfig) -> CompiledContext {
109→    if blocks.is_empty() {
110→        return CompiledContext {
111→            system_messages: Vec::new(),
112→            total_tokens: 0,
113→            dropped_blocks: Vec::new(),
114→        };
115→    }
116→
117→    // Sort blocks by assembly order, preserving relative order for same kind
118→    let mut sorted: Vec<&ContextBlock> = blocks.iter().filter(|b| !b.content.is_empty()).collect();
119→    sorted.sort_by_key(|b| b.kind.order());
120→
121→    // Truncate each block to its per-kind budget
122→    let truncated: Vec<(&ContextBlock, &str)> = sorted
123→        .iter()
124→        .map(|block| {
125→            let content = if let Some(budget) = config.budget_for(block.kind) {
126→                truncate_to_budget(&block.content, budget)
127→            } else {
128→                block.content.as_str()
129→            };
130→            (*block, content)
131→        })
132→        .collect();
133→
134→    // Calculate total tokens
135→    let total: usize = truncated.iter().map(|(_, c)| estimate_tokens(c)).sum();
136→
137→    if total <= config.total_budget {
138→        // Everything fits
139→        let system_messages = truncated
140→            .iter()
141→            .map(|(_, content)| ChatMessage::system(*content))
142→            .collect();
143→        return CompiledContext {
144→            system_messages,
145→            total_tokens: total,
146→            dropped_blocks: Vec::new(),
147→        };
148→    }
149→
150→    // Need to drop lowest-priority blocks. Sort by priority ascending (lowest first to drop).
151→    let mut indexed: Vec<(usize, &ContextBlock, &str, usize)> = truncated
152→        .iter()
153→        .enumerate()
154→        .map(|(i, (block, content))| (i, *block, *content, estimate_tokens(content)))
155→        .collect();
156→
157→    // Sort by priority ascending — lowest priority gets dropped first.
158→    // Persona (priority 255 by convention) should never be dropped.
159→    indexed.sort_by(|a, b| a.1.priority.cmp(&b.1.priority));
160→
161→    let mut budget_remaining = config.total_budget;
162→    let mut keep_indices: Vec<usize> = Vec::new();
163→    let mut dropped_blocks: Vec<ContextBlockKind> = Vec::new();
164→
165→    // Process highest priority first (from the end)
166→    for &(original_idx, block, _, tokens) in indexed.iter().rev() {
167→        if tokens <= budget_remaining {
168→            keep_indices.push(original_idx);
169→            budget_remaining = budget_remaining.saturating_sub(tokens);
170→        } else {
171→            dropped_blocks.push(block.kind);
172→        }
173→    }
174→
175→    // Restore original assembly order
176→    keep_indices.sort_unstable();
177→
178→    let system_messages: Vec<ChatMessage> = keep_indices
179→        .iter()
180→        .map(|&i| ChatMessage::system(truncated[i].1))
181→        .collect();
182→
183→    let total_tokens: usize = keep_indices
184→        .iter()
185→        .map(|&i| estimate_tokens(truncated[i].1))
186→        .sum();
187→
188→    CompiledContext {
189→        system_messages,
190→        total_tokens,
191→        dropped_blocks,
192→    }
193→}
