205→fn resolve_data_dir(data_dir: &PathBuf) -> anyhow::Result<PathBuf> {
206→    let workspace_root = std::env::current_dir()?;
207→    Ok(if data_dir.is_relative() {
208→        workspace_root.join(data_dir)
209→    } else {
210→        data_dir.clone()
211→    })
212→}
