214→fn read_last_session_hint(data_dir: &Path) -> Option<String> {
215→    let path = data_dir.join("last_session");
216→    let raw = std::fs::read_to_string(path).ok()?;
217→    let session = raw.trim();
218→    if session.is_empty() {
219→        None
220→    } else {
221→        Some(session.to_owned())
222→    }
223→}
224→
225→fn persist_last_session_hint(data_dir: &Path, session: &str) -> anyhow::Result<()> {
226→    std::fs::create_dir_all(data_dir)?;
227→    std::fs::write(data_dir.join("last_session"), session)?;
228→    Ok(())
229→}
