231→/// Resolve session via the daemon's HTTP API first, falling back to local hints.
232→/// This avoids opening the journal (which would conflict with the daemon's redb lock).
233→async fn resolve_session(
234→    data_dir: &Path,
235→    requested: Option<String>,
236→    base_url: Option<&str>,
237→) -> String {
238→    if let Some(session) = requested {
239→        return session;
240→    }
241→
242→    if let Some(session) = read_last_session_hint(data_dir) {
243→        return session;
244→    }
245→
246→    // Try the HTTP API if a daemon URL is available (avoids redb lock conflict).
247→    if let Some(url) = base_url {
248→        if let Some(session) = cli_run::resolve_session_via_api(url).await {
249→            return session;
250→        }
251→    }
252→
253→    "default".to_owned()
254→}
