 24→fn envelope_to_record(envelope: aios_protocol::EventEnvelope) -> Result<EventRecord, KernelError> {
 25→    Ok(EventRecord {
 26→        event_id: envelope.event_id,
 27→        session_id: envelope.session_id,
 28→        agent_id: envelope.agent_id,
 29→        branch_id: envelope.branch_id,
 30→        sequence: envelope.seq,
 31→        timestamp: micros_to_datetime(envelope.timestamp)?,
 32→        actor: envelope.actor,
 33→        schema: envelope.schema,
 34→        causation_id: envelope.parent_id,
 35→        correlation_id: envelope.metadata.get("correlation_id").cloned(),
 36→        trace_id: envelope.trace_id,
 37→        span_id: envelope.span_id,
 38→        digest: envelope.digest,
 39→        kind: envelope.kind,
 40→    })
 41→}
