  1→use crate::event_map;
  2→use arcan_core::protocol::AgentEvent;
  3→use arcan_store::session::{AppendEvent, EventRecord, SessionRepository, StoreError};
  4→use chrono::{DateTime, Utc};
  5→use lago_core::{BranchId, EventQuery, Journal, SeqNo, SessionId};
  6→use std::sync::Arc;
  7→
  8→/// A [`SessionRepository`] implementation backed by a Lago [`Journal`].
  9→///
 10→/// This bridges Arcan's synchronous `SessionRepository` trait with Lago's
 11→/// async `Journal` trait. The sync/async boundary is crossed using
 12→/// `Handle::current().block_on()`, which is safe because the Arcan
 13→/// `AgentLoop` runs the orchestrator inside `tokio::task::spawn_blocking`.
 14→pub struct LagoSessionRepository {
 15→    journal: Arc<dyn Journal>,
 16→    default_branch: BranchId,
 17→}
 18→
 19→impl LagoSessionRepository {
 20→    pub fn new(journal: Arc<dyn Journal>) -> Self {
 21→        Self {
 22→            journal,
 23→            default_branch: BranchId::from("main"),
 24→        }
 25→    }
 26→
 27→    /// Run an async future on the current tokio runtime from a sync context.
 28→    fn block_on<F: std::future::Future>(&self, f: F) -> F::Output {
 29→        tokio::runtime::Handle::current().block_on(f)
 30→    }
 31→
 32→    fn session_id(&self, id: &str) -> SessionId {
 33→        SessionId::from(id.to_string())
 34→    }
 35→}
 36→
 37→impl SessionRepository for LagoSessionRepository {
 38→    fn append(&self, request: AppendEvent) -> Result<EventRecord, StoreError> {
 39→        let session_id = self.session_id(&request.session_id);
 40→        let branch_id = BranchId::from(request.branch_id.clone());
 41→        let seq: SeqNo = 0;
 42→
 43→        // Extract run_id from the event for the envelope.
 44→        let run_id = extract_run_id(&request.event);
 45→        let arcan_event_id = uuid::Uuid::new_v4().to_string();
 46→
 47→        let envelope = event_map::arcan_to_lago(
 48→            &session_id,
 49→            &branch_id,
 50→            seq,
 51→            &run_id,
 52→            &request.event,
 53→            &arcan_event_id,
 54→        );
 55→
