 11→fn tool_err(msg: impl Into<String>) -> CoreError {
 12→    CoreError::ToolExecution {
 13→        tool_name: "memory".to_string(),
 14→        message: msg.into(),
 15→    }
 16→}
 17→
 18→fn parse_scope(s: &str) -> Result<MemoryScope, CoreError> {
 19→    match s {
 20→        "session" => Ok(MemoryScope::Session),
 21→        "user" => Ok(MemoryScope::User),
 22→        "agent" => Ok(MemoryScope::Agent),
 23→        "org" => Ok(MemoryScope::Org),
 24→        other => Err(tool_err(format!("invalid scope: {other}"))),
 25→    }
 26→}
