153→impl Tool for MemoryProposeTool {
154→    fn definition(&self) -> ToolDefinition {
155→        ToolDefinition {
156→            name: "memory_propose".to_string(),
157→            description: "Propose new memory entries for storage. Creates a MemoryProposed event."
158→                .to_string(),
159→            input_schema: json!({
160→                "type": "object",
161→                "properties": {
162→                    "scope": {
163→                        "type": "string",
164→                        "enum": ["session", "user", "agent", "org"],
165→                        "description": "Memory scope for the proposal"
166→                    },
167→                    "entries": {
168→                        "type": "array",
169→                        "items": {
170→                            "type": "object",
171→                            "properties": {
172→                                "content": { "type": "string" }
173→                            },
174→                            "required": ["content"]
175→                        },
176→                        "description": "Memory entries to propose"
177→                    }
178→                },
179→                "required": ["scope", "entries"]
180→            }),
181→            title: None,
182→            output_schema: None,
183→            annotations: None,
184→            category: Some("memory".to_string()),
185→            tags: vec!["memory".to_string()],
186→            timeout_secs: None,
187→        }
188→    }
189→
190→    fn execute(&self, call: &ToolCall, ctx: &ToolContext) -> Result<ToolResult, CoreError> {
191→        let session_id = SessionId::from_string(&ctx.session_id);
192→        let branch_id = &self.default_branch_id;
193→
194→        let scope_str = call
195→            .input
196→            .get("scope")
197→            .and_then(serde_json::Value::as_str)
198→            .ok_or_else(|| tool_err("missing 'scope' field".to_string()))?;
199→
200→        let scope = parse_scope(scope_str)?;
201→
202→        let entries = call
203→            .input
204→            .get("entries")
205→            .and_then(serde_json::Value::as_array)
206→            .ok_or_else(|| tool_err("missing or invalid 'entries' field".to_string()))?;
207→
208→        if entries.is_empty() {
209→            return Err(tool_err("entries must not be empty".to_string()));
210→        }
211→
212→        // Validate entries have content
213→        for entry in entries {
214→            if entry
215→                .get("content")
216→                .and_then(serde_json::Value::as_str)
217→                .is_none()
218→            {
219→                return Err(tool_err(
220→                    "each entry must have a 'content' string field".to_string(),
221→                ));
222→            }
223→        }
224→
225→        let proposal_id = MemoryId::new();
226→        let entries_json = serde_json::to_string(entries)
227→            .map_err(|e| tool_err(format!("serialize error: {e}")))?;
228→        let entries_ref = BlobHash::from_hex(format!("{:x}", md5_hash(entries_json.as_bytes())));
229→
230→        let envelope = EventEnvelope {
231→            event_id: EventId::new(),
232→            session_id,
233→            branch_id: branch_id.clone(),
234→            run_id: Some(RunId::from_string(&ctx.run_id)),
235→            seq: 0,
236→            timestamp: EventEnvelope::now_micros(),
237→            parent_id: None,
238→            payload: EventPayload::MemoryProposed {
239→                scope,
240→                proposal_id: proposal_id.clone().into(),
241→                entries_ref: entries_ref.into(),
242→                source_run_id: Some(ctx.run_id.clone()),
243→            },
244→            metadata: std::collections::HashMap::new(),
245→            schema_version: 1,
246→        };
247→
248→        self.block_on(self.journal.append(envelope))
249→            .map_err(|e| tool_err(format!("journal append error: {e}")))?;
250→
251→        Ok(ToolResult {
252→            call_id: call.call_id.clone(),
253→            tool_name: call.tool_name.clone(),
254→            output: json!({
255→                "proposal_id": proposal_id.as_str(),
256→                "entry_count": entries.len(),
257→            }),
258→            content: None,
259→            is_error: false,
260→            state_patch: None,
261→        })
262→    }
263→}
