297→impl Tool for MemoryCommitTool {
298→    fn definition(&self) -> ToolDefinition {
299→        ToolDefinition {
300→            name: "memory_commit".to_string(),
301→            description: "Commit a previously proposed memory. Creates a MemoryCommitted event."
302→                .to_string(),
303→            input_schema: json!({
304→                "type": "object",
305→                "properties": {
306→                    "proposal_id": {
307→                        "type": "string",
308→                        "description": "ID of the proposal to commit"
309→                    },
310→                    "supersedes": {
311→                        "type": "string",
312→                        "description": "Optional ID of a memory this replaces"
313→                    }
314→                },
315→                "required": ["proposal_id"]
316→            }),
317→            title: None,
318→            output_schema: None,
319→            annotations: None,
320→            category: Some("memory".to_string()),
321→            tags: vec!["memory".to_string()],
322→            timeout_secs: None,
323→        }
324→    }
325→
326→    fn execute(&self, call: &ToolCall, ctx: &ToolContext) -> Result<ToolResult, CoreError> {
327→        let session_id = SessionId::from_string(&ctx.session_id);
328→        let branch_id = &self.default_branch_id;
329→
330→        let proposal_id_str = call
331→            .input
332→            .get("proposal_id")
333→            .and_then(serde_json::Value::as_str)
334→            .ok_or_else(|| tool_err("missing 'proposal_id' field".to_string()))?;
335→
336→        if proposal_id_str.is_empty() {
337→            return Err(tool_err("proposal_id must not be empty".to_string()));
338→        }
339→
340→        let supersedes = call
341→            .input
342→            .get("supersedes")
343→            .and_then(serde_json::Value::as_str)
344→            .map(MemoryId::from_string);
345→
346→        let memory_id = MemoryId::new();
347→        let committed_ref = BlobHash::from_hex(format!("committed-{proposal_id_str}"));
348→
349→        let envelope = EventEnvelope {
350→            event_id: EventId::new(),
351→            session_id,
352→            branch_id: branch_id.clone(),
353→            run_id: None,
354→            seq: 0,
355→            timestamp: EventEnvelope::now_micros(),
356→            parent_id: None,
357→            payload: EventPayload::MemoryCommitted {
358→                scope: MemoryScope::Session, // Default scope for commit
359→                memory_id: memory_id.clone().into(),
360→                committed_ref: committed_ref.into(),
361→                supersedes: supersedes.map(Into::into),
362→            },
363→            metadata: std::collections::HashMap::new(),
364→            schema_version: 1,
365→        };
366→
367→        self.block_on(self.journal.append(envelope))
368→            .map_err(|e| tool_err(format!("journal append error: {e}")))?;
369→
370→        Ok(ToolResult {
371→            call_id: call.call_id.clone(),
372→            tool_name: call.tool_name.clone(),
373→            output: json!({
374→                "memory_id": memory_id.as_str(),
375→                "committed": true,
376→            }),
377→            content: None,
378→            is_error: false,
379→            state_patch: None,
380→        })
381→    }
382→}
