 11→        impl $name {
 12→            pub fn new() -> Self {
 13→                Self(Ulid::new().to_string())
 14→            }
 15→
 16→            pub fn from_string(s: impl Into<String>) -> Self {
 17→                Self(s.into())
 18→            }
 19→
 20→            pub fn as_str(&self) -> &str {
 21→                &self.0
 22→            }
