 26→            fn default() -> Self {
 27→                Self::new()
 28→            }
 29→        }
 30→
 31→        impl fmt::Display for $name {
 32→            fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
 33→                write!(f, "{}", self.0)
