 35→        }
 36→
 37→        impl From<String> for $name {
 38→            fn from(s: String) -> Self {
 39→                Self(s)
 40→            }
 41→        }
 42→
 43→        impl From<&str> for $name {
 44→            fn from(s: &str) -> Self {
 45→                Self(s.to_string())
 46→            }
 47→        }
 48→
 49→        impl AsRef<str> for $name {
