256→fn run_serve(
257→    data_dir: &Path,
258→    port: u16,
259→    _max_iterations: u32,
260→    _approval_timeout: u64,
261→) -> anyhow::Result<()> {
262→    let workspace_root = std::env::current_dir()?;
263→
264→    // --- Lago persistence ---
265→    let journal_path = data_dir.join("journal.redb");
266→    let blobs_path = data_dir.join("blobs");
267→    std::fs::create_dir_all(&blobs_path)?;
268→
269→    tracing::info!(
270→        workspace = %workspace_root.display(),
271→        journal = %journal_path.display(),
272→        blobs = %blobs_path.display(),
273→        "Starting arcan"
274→    );
275→
276→    let journal = RedbJournal::open(&journal_path)?;
277→    let _blob_store = Arc::new(lago_store::BlobStore::open(&blobs_path)?);
278→    let journal: Arc<dyn lago_core::Journal> = Arc::new(journal);
279→
280→    // --- Policies ---
281→    let fs_policy = FsPolicy::new(workspace_root.clone());
282→    let sandbox_policy = SandboxPolicy {
283→        workspace_root: workspace_root.clone(),
284→        shell_enabled: true,
285→        network: NetworkPolicy::AllowAll,
286→        allowed_env: BTreeSet::new(),
287→        max_execution_ms: 10_000,
288→        max_stdout_bytes: 1024 * 1024,
289→        max_stderr_bytes: 1024 * 1024,
290→        max_processes: 10,
291→        max_memory_mb: 512,
292→    };
293→
294→    // --- Tools ---
295→    let mut registry = ToolRegistry::default();
296→    registry.register(ReadFileTool::new(fs_policy.clone()));
297→    registry.register(WriteFileTool::new(fs_policy.clone()));
298→    registry.register(ListDirTool::new(fs_policy.clone()));
299→    registry.register(EditFileTool::new(fs_policy.clone()));
300→    registry.register(GlobTool::new(fs_policy.clone()));
301→    registry.register(GrepTool::new(fs_policy));
302→
303→    let runner = Box::new(LocalCommandRunner);
304→    registry.register(BashTool::new(sandbox_policy, runner));
305→
306→    let memory_dir = data_dir.join("memory");
307→    std::fs::create_dir_all(&memory_dir)?;
308→    registry.register(ReadMemoryTool::new(memory_dir.clone()));
309→    registry.register(WriteMemoryTool::new(memory_dir));
310→
311→    // --- Governed memory tools (event-sourced via Lago) ---
312→    let memory_projection = Arc::new(RwLock::new(MemoryProjection::new()));
313→    registry.register(MemoryQueryTool::new(memory_projection));
314→    registry.register(MemoryProposeTool::new(journal.clone()));
315→    registry.register(MemoryCommitTool::new(journal.clone()));
316→
317→    // --- Provider ---
318→    // Selection order: ARCAN_PROVIDER env var > auto-detect from API keys > MockProvider
319→    let provider_name = std::env::var("ARCAN_PROVIDER").unwrap_or_default();
320→    let provider: Arc<dyn Provider> = match provider_name.as_str() {
321→        "mock" => {
322→            tracing::warn!("Provider: MockProvider (forced via ARCAN_PROVIDER=mock)");
323→            Arc::new(MockProvider)
324→        }
325→        "openai" => match arcan_provider::openai::OpenAiConfig::openai_from_env() {
326→            Ok(config) => {
327→                tracing::info!(model = %config.model, "Provider: OpenAI");
328→                Arc::new(arcan_provider::openai::OpenAiCompatibleProvider::new(
329→                    config,
330→                ))
331→            }
332→            Err(e) => {
333→                tracing::error!("ARCAN_PROVIDER=openai but config failed: {e}");
334→                return Err(e.into());
335→            }
336→        },
337→        "ollama" => match arcan_provider::openai::OpenAiConfig::ollama_from_env() {
338→            Ok(config) => {
339→                tracing::info!(model = %config.model, base_url = %config.base_url, "Provider: Ollama");
340→                Arc::new(arcan_provider::openai::OpenAiCompatibleProvider::new(
341→                    config,
342→                ))
343→            }
344→            Err(e) => {
345→                tracing::error!("ARCAN_PROVIDER=ollama but config failed: {e}");
346→                return Err(e.into());
347→            }
348→        },
349→        "anthropic" => match AnthropicConfig::from_env() {
350→            Ok(config) => {
351→                tracing::info!(model = %config.model, "Provider: Anthropic");
352→                Arc::new(AnthropicProvider::new(config))
353→            }
354→            Err(e) => {
355→                tracing::error!("ARCAN_PROVIDER=anthropic but config failed: {e}");
356→                return Err(e.into());
357→            }
358→        },
359→        // Auto-detect: try providers in order
360→        _ => {
361→            if let Ok(config) = AnthropicConfig::from_env() {
362→                tracing::info!(model = %config.model, "Provider: Anthropic (auto-detected)");
363→                Arc::new(AnthropicProvider::new(config))
364→            } else if let Ok(config) = arcan_provider::openai::OpenAiConfig::openai_from_env() {
365→                tracing::info!(model = %config.model, "Provider: OpenAI (auto-detected)");
366→                Arc::new(arcan_provider::openai::OpenAiCompatibleProvider::new(
367→                    config,
368→                ))
369→            } else {
370→                tracing::warn!(
371→                    "Provider: MockProvider (set ARCAN_PROVIDER or API key env vars for real LLM)"
372→                );
373→                Arc::new(MockProvider)
374→            }
375→        }
376→    };
377→
378→    // --- Canonical aiOS runtime adapters ---
379→    let event_store: Arc<dyn EventStorePort> =
380→        Arc::new(LagoAiosEventStoreAdapter::new(journal.clone()));
381→    // Shared handle: starts empty, filled after runtime creation.
382→    let streaming_sender: StreamingSenderHandle = Arc::new(std::sync::Mutex::new(None));
383→    let provider_adapter: Arc<dyn ModelProviderPort> = Arc::new(ArcanProviderAdapter::new(
384→        provider,
385→        registry.definitions(),
386→        streaming_sender.clone(),
387→    ));
388→    let observer = Arc::new(LakeFsObserver {
389→        workspace_root: workspace_root.clone(),
390→        journal: journal.clone(),
391→        blob_store: _blob_store,
392→    });
393→    let tool_harness: Arc<dyn ToolHarnessPort> =
394→        Arc::new(ArcanHarnessAdapter::new(registry).with_observer(observer));
395→    let policy_gate: Arc<dyn PolicyGatePort> =
396→        Arc::new(ArcanPolicyAdapter::new(aios_protocol::PolicySet::default()));
397→    let approvals: Arc<dyn ApprovalPort> = Arc::new(ArcanApprovalAdapter::new());
398→
399→    let runtime = Arc::new(KernelRuntime::new(
400→        RuntimeConfig::new(data_dir.to_path_buf()),
401→        event_store,
402→        provider_adapter,
403→        tool_harness,
404→        approvals,
405→        policy_gate,
406→    ));
407→
408→    // Wire the broadcast sender now that the runtime exists.
409→    *streaming_sender.lock().unwrap() = Some(runtime.event_sender());
410→
411→    // Build provider stack and blocking HTTP clients before entering Tokio runtime.
412→    let data_dir_owned = data_dir.to_path_buf();
413→    let tokio_runtime = tokio::runtime::Builder::new_multi_thread()
414→        .enable_all()
415→        .build()?;
416→
417→    tokio_runtime.block_on(async move {
418→        // --- HTTP Server ---
419→        let router = create_canonical_router(runtime);
420→        let addr = std::net::SocketAddr::from(([127, 0, 0, 1], port));
421→        let listener = TcpListener::bind(addr).await?;
422→
423→        tracing::info!(%addr, "Listening");
424→        axum::serve(listener, router)
425→            .with_graceful_shutdown(shutdown_signal())
426→            .await?;
427→
428→        // Clean up PID file on graceful shutdown.
429→        daemon::remove_pid_file(&data_dir_owned);
430→
431→        tracing::info!("Server shut down gracefully");
432→        Ok(())
433→    })
434→}
