459→async fn run_message(
460→    data_dir: PathBuf,
461→    port: u16,
462→    message: String,
463→    session: Option<String>,
464→    url: Option<String>,
465→    json_output: bool,
466→) -> anyhow::Result<()> {
467→    // Ensure daemon is running first.
468→    let base_url = match url {
469→        Some(u) => u,
470→        None => daemon::ensure_daemon(&data_dir, port).await?,
471→    };
472→
473→    // Resolve session via API (no direct journal access).
474→    let session = resolve_session(&data_dir, session, Some(&base_url)).await;
475→
476→    if let Err(error) = persist_last_session_hint(&data_dir, &session) {
477→        tracing::warn!(%error, "failed to persist last_session hint");
478→    }
479→
480→    let exit_code = cli_run::run_cli(&base_url, &session, &message, json_output).await?;
481→    if exit_code != 0 {
482→        std::process::exit(exit_code);
483→    }
484→    Ok(())
485→}
