 56→/// Run a single message against the daemon and print the response to stdout.
 57→///
 58→/// Opens an SSE stream at `/events/stream` before firing `/runs`, so events
 59→/// (including ephemeral streaming text deltas) render in real time.
 60→pub async fn run_cli(
 61→    base_url: &str,
 62→    session_id: &str,
 63→    message: &str,
 64→    json_output: bool,
 65→) -> anyhow::Result<i32> {
 66→    let client = Client::new();
 67→
 68→    // Ensure session exists (creates if needed via POST /sessions).
 69→    client
 70→        .post(format!("{base_url}/sessions"))
 71→        .json(&serde_json::json!({ "session_id": session_id }))
 72→        .send()
 73→        .await?;
 74→
 75→    // Get the current event cursor so we only see new events.
 76→    let events_response = client
 77→        .get(format!(
 78→            "{base_url}/sessions/{session_id}/events?limit=10000"
 79→        ))
 80→        .send()
 81→        .await?;
 82→    let cursor = if events_response.status().is_success() {
 83→        let body: serde_json::Value = events_response.json().await?;
 84→        body.get("events")
 85→            .and_then(|v| v.as_array())
 86→            .and_then(|arr| arr.last())
 87→            .and_then(|e| e.get("sequence"))
 88→            .and_then(serde_json::Value::as_u64)
 89→            .unwrap_or(0)
 90→    } else {
 91→        0
 92→    };
 93→
 94→    // Open SSE stream before firing the run.
 95→    let stream_url =
 96→        format!("{base_url}/sessions/{session_id}/events/stream?cursor={cursor}&format=canonical");
 97→    let mut event_source = EventSource::get(&stream_url);
 98→
 99→    // Fire the run concurrently (don't await completion before reading SSE).
100→    let run_url = format!("{base_url}/sessions/{session_id}/runs");
101→    let run_body = serde_json::json!({ "objective": message });
102→    let run_client = client.clone();
103→    let run_handle = tokio::spawn(async move {
104→        let result = run_client.post(&run_url).json(&run_body).send().await;
105→        match result {
106→            Ok(resp) if !resp.status().is_success() => {
107→                let status = resp.status();
108→                let body = resp.text().await.unwrap_or_default();
109→                Err(anyhow::anyhow!("Run request failed ({status}): {body}"))
110→            }
111→            Ok(_) => Ok(()),
112→            Err(e) => Err(anyhow::anyhow!("Run request failed: {e}")),
113→        }
114→    });
115→
116→    let mut exit_code = 0;
117→    let mut stdout = std::io::stdout().lock();
118→    // Track whether we've received ephemeral streaming text (sequence 0).
119→    // If so, we skip persisted text events to avoid duplicate output.
120→    let mut saw_streaming_text = false;
121→
122→    // Read SSE events as they arrive.
123→    while let Some(event) = event_source.next().await {
124→        match event {
125→            Ok(SseEvent::Open) => {}
126→            Ok(SseEvent::Message(msg)) => {
127→                if json_output {
128→                    let _ = writeln!(stdout, "{}", msg.data);
129→                    let _ = stdout.flush();
130→                }
131→
132→                let Ok(record) = serde_json::from_str::<EventRecord>(&msg.data) else {
133→                    continue;
134→                };
135→
136→                if !json_output {
137→                    match &record.kind {
138→                        EventKind::TextDelta { delta }
139→                        | EventKind::AssistantTextDelta { delta } => {
140→                            if record.sequence == 0 {
141→                                // Ephemeral streaming delta — display immediately.
142→                                saw_streaming_text = true;
143→                                let _ = write!(stdout, "{delta}");
144→                                let _ = stdout.flush();
145→                            } else if !saw_streaming_text {
146→                                // Persisted delta, but only show if we didn't
147→                                // already see streaming text.
148→                                let _ = write!(stdout, "{delta}");
149→                                let _ = stdout.flush();
150→                            }
151→                            // else: skip persisted duplicate
152→                        }
153→                        EventKind::Message { content } => {
154→                            if !saw_streaming_text {
155→                                let _ = write!(stdout, "{content}");
156→                                let _ = stdout.flush();
157→                            }
158→                        }
159→                        EventKind::ToolCallRequested { tool_name } => {
160→                            let _ = writeln!(stdout, "\n[tool: {tool_name}] requested");
161→                        }
162→                        EventKind::ToolCallStarted { tool_name } => {
163→                            let _ = writeln!(stdout, "[tool: {tool_name}] started");
164→                        }
165→                        EventKind::ToolCallCompleted { tool_name } => {
166→                            let _ = writeln!(stdout, "[tool: {tool_name}] OK");
167→                        }
168→                        EventKind::ToolCallFailed { tool_name, error } => {
169→                            let _ = writeln!(stdout, "[tool: {tool_name}] ERROR: {error}");
170→                        }
171→                        EventKind::RunFinished {} => {
172→                            let _ = writeln!(stdout);
173→                            event_source.close();
174→                            break;
175→                        }
176→                        EventKind::RunErrored { error } => {
177→                            let _ = writeln!(stdout, "\nERROR: {error}");
178→                            exit_code = 1;
179→                            event_source.close();
180→                            break;
181→                        }
182→                        EventKind::Other => {}
183→                    }
184→                }
185→
186→                // In JSON mode, also detect run termination events.
187→                if json_output {
188→                    match &record.kind {
189→                        EventKind::RunFinished {} => {
190→                            event_source.close();
191→                            break;
192→                        }
193→                        EventKind::RunErrored { .. } => {
194→                            exit_code = 1;
195→                            event_source.close();
196→                            break;
197→                        }
198→                        _ => {}
199→                    }
200→                }
201→            }
202→            Err(_) => {
203→                // SSE connection closed or errored — stop reading.
204→                break;
205→            }
206→        }
207→    }
208→
209→    // Ensure the run request completed (surface errors).
210→    if let Err(e) = run_handle.await? {
211→        // Only report run errors if we didn't already get a RunErrored event.
212→        if exit_code == 0 {
213→            let _ = writeln!(stdout, "\nERROR: {e}");
214→            exit_code = 1;
215→        }
216→    }
217→
218→    Ok(exit_code)
219→}
