 670→                .map_err(|_| CoreError::Provider("scripted provider lock poisoned".to_string()))?;
 671→            let idx = *cursor;
 672→            let Some(turn) = self.turns.get(idx) else {
 673→                return Err(CoreError::Provider("no scripted turn left".to_string()));
