 929→    #[test]
 930→    fn budget_exceeded_when_iterations_exhausted() {
 931→        // Provider always returns ToolUse but no tool call directives → continues loop
 932→        // Actually, we need it to keep looping. Use a tool that works, but provider
 933→        // always asks for more.
 934→        let provider = ScriptedProvider {
 935→            turns: vec![
 936→                ModelTurn {
 937→                    directives: vec![ModelDirective::ToolCall {
 938→                        call: ToolCall {
 939→                            call_id: "c1".to_string(),
 940→                            tool_name: "echo".to_string(),
 941→                            input: json!({"value": "1"}),
 942→                        },
 943→                    }],
 944→                    stop_reason: ModelStopReason::ToolUse,
 945→                    usage: None,
 946→                },
 947→                ModelTurn {
 948→                    directives: vec![ModelDirective::ToolCall {
 949→                        call: ToolCall {
 950→                            call_id: "c2".to_string(),
 951→                            tool_name: "echo".to_string(),
 952→                            input: json!({"value": "2"}),
 953→                        },
 954→                    }],
 955→                    stop_reason: ModelStopReason::ToolUse,
 956→                    usage: None,
