1140→    #[test]
1141→    fn cancellation_stops_run() {
1142→        let provider = ScriptedProvider {
1143→            turns: vec![
1144→                ModelTurn {
1145→                    directives: vec![ModelDirective::ToolCall {
1146→                        call: ToolCall {
1147→                            call_id: "c1".to_string(),
1148→                            tool_name: "echo".to_string(),
1149→                            input: json!({"value": "1"}),
1150→                        },
1151→                    }],
1152→                    stop_reason: ModelStopReason::ToolUse,
1153→                    usage: None,
1154→                },
1155→                ModelTurn {
1156→                    directives: vec![ModelDirective::FinalAnswer {
1157→                        text: "should not reach".to_string(),
1158→                    }],
1159→                    stop_reason: ModelStopReason::EndTurn,
1160→                    usage: None,
1161→                },
1162→            ],
1163→            cursor: Mutex::new(0),
1164→        };
1165→
1166→        let mut tools = ToolRegistry::default();
1167→        tools.register(EchoTool);
1168→
1169→        let orchestrator = Orchestrator::new(
1170→            Arc::new(provider),
1171→            tools,
1172→            Vec::new(),
1173→            OrchestratorConfig {
1174→                max_iterations: 10,
1175→                context: None,
1176→                context_compiler: None,
1177→            },
1178→        );
1179→
1180→        // Set cancellation flag before the second iteration
1181→        let cancel = Arc::new(AtomicBool::new(false));
1182→        let cancel_clone = cancel.clone();
1183→        let call_count = Arc::new(Mutex::new(0u32));
1184→        let call_count_clone = call_count.clone();
1185→
1186→        let output = orchestrator.run_cancellable(
1187→            RunInput {
1188→                run_id: "run-1".to_string(),
1189→                session_id: "s1".to_string(),
1190→                branch_id: "main".to_string(),
1191→                messages: vec![ChatMessage::user("test")],
1192→                state: AppState::default(),
1193→            },
1194→            Some(&cancel_clone),
1195→            move |event| {
1196→                // Cancel after first iteration completes
1197→                if matches!(event, AgentEvent::ToolCallCompleted { .. }) {
1198→                    let mut count = call_count_clone.lock().unwrap();
1199→                    *count += 1;
1200→                    if *count >= 1 {
1201→                        cancel.store(true, Ordering::Relaxed);
1202→                    }
1203→                }
1204→            },
1205→        );
1206→
1207→        assert_eq!(output.reason, RunStopReason::Cancelled);
1208→        // Should not have a final answer since we cancelled
1209→        assert!(output.final_answer.is_none());
1210→    }
