### 4. Precedence Chain

The resolution order (lowest to highest priority):

```
hardcoded defaults --> global config file --> project-local config file --> env vars --> CLI flags
```

This is implemented via a `ResolvedConfig` struct that applies each layer in order:

```rust
/// Fully resolved configuration with all layers applied.
pub struct ResolvedConfig {
    pub provider: String,
    pub model: Option<String>,  // None = let provider choose default
    pub port: u16,
    pub data_dir: PathBuf,
    pub max_iterations: u32,
    pub approval_timeout: u64,
    pub provider_config: Option<ProviderConfig>,
}

impl ResolvedConfig {
    pub fn resolve(cli: &Cli, file_config: &ArcanConfig) -> Self {
        // 1. Start with hardcoded defaults
        let mut provider = String::new(); // empty = auto-detect
        let mut model: Option<String> = None;
        let mut port: u16 = 3000;
        let mut max_iterations: u32 = 10;
        let mut approval_timeout: u64 = 300;

        // 2. Apply file config
        if let Some(p) = &file_config.defaults.provider { provider = p.clone(); }
        if let Some(m) = &file_config.defaults.model { model = Some(m.clone()); }
        if let Some(p) = file_config.defaults.port { port = p; }
        if let Some(i) = file_config.agent.max_iterations { max_iterations = i; }
        if let Some(t) = file_config.agent.approval_timeout { approval_timeout = t; }

        // 3. Apply env vars
        if let Ok(p) = std::env::var("ARCAN_PROVIDER") { if !p.is_empty() { provider = p; } }
        if let Ok(m) = std::env::var("ARCAN_MODEL") { model = Some(m); }
        if let Ok(p) = std::env::var("ARCAN_PORT") { if let Ok(p) = p.parse() { port = p; } }

        // 4. Apply CLI flags (highest priority)
        if let Some(p) = &cli.provider { provider = p.clone(); }
        if let Some(m) = &cli.model { model = Some(m.clone()); }
        if let Some(p) = cli.port { port = p; }

        // Resolve provider-specific config from file
        let provider_config = if !provider.is_empty() {
            file_config.providers.get(&provider).cloned()
        } else {
            None
        };

        Self { provider, model, port, data_dir: cli.data_dir.clone(), max_iterations, approval_timeout, provider_config }
    }
}
```

